impl SoundnessSpectrum {
    /// Compute the cohomological gradient — the rate of change between
    /// adjacent layers. Each element is |layer[k+1] - layer[k]|.
    /// Sharp gradients indicate dimensional boundaries where the
    /// observation's structure changes character.
    pub fn gradient(&self) -> [Q; 10] {
        let layers = self.layers();
        let mut grad = std::array::from_fn(|_| Q::zero());
        for i in 0..10 {
            let diff = &layers[i + 1] - &layers[i];
            grad[i] = if diff < Q::zero() { -diff } else { diff };
        }
        grad
    }

    /// The 11 layers as an array for iteration.
    pub fn layers(&self) -> [Q; 11] {
        [
            self.value_identity.clone(),
            self.spatial_position.clone(),
            self.adjacency_coherence.clone(),
            self.cluster_structure.clone(),
            self.symmetry_order.clone(),
            self.boundary_behavior.clone(),
            self.periodicity.clone(),
            self.value_transition.clone(),
            self.dimensional_bridge.clone(),
            self.cross_pair_consistency.clone(),
            self.residual_structure.clone(),
        ]
    }

    /// Mean soundness across all 11 layers.
    /// Not a gate — a continuous measurement of overall coherence.
    pub fn mean_soundness(&self) -> Q {
        let layers = self.layers();
        let sum: Q = layers.iter().fold(Q::zero(), |acc, l| acc + l);
        Q::new(sum.numer().clone(), sum.denom() * BigInt::from(11))
    }

    /// Maximum gradient — the sharpest dimensional boundary.
    /// High = one dimension has a sharp obstruction relative to neighbors.
    /// Low = smooth spectrum, the observation is cohomologically consonant.
    pub fn max_gradient(&self) -> Q {
        let grad = self.gradient();
        grad.into_iter().max().unwrap_or(Q::zero())
    }
}

