/// Dimensionless refractive lens — the node's algebraic state projected
/// as a modulation operator for observations of any dimension.
///
/// The lens bridges the 3D internal Δ_k to ND observations through
/// algebraic resonance: torsion orders from the Delta's antisymmetric
/// structure define which periodicities the entity is sensitive to.
/// The relational weights from entry magnitudes determine bias direction.
#[derive(Debug, Clone)]
pub struct RefractiveLens {
    /// Torsion orders derived from Δ_k's antisymmetric structure.
    /// Each order defines a spatial periodicity the entity resonates with.
    /// Extracted from prime factorization of entry numerators and denominators.
    pub torsion_orders: Vec<u32>,
    /// Relational weights from Δ_k entries — sign determines bias direction,
    /// magnitude determines weight of the corresponding torsion channel.
    pub relational_weights: Vec<Q>,
}

/// Extract prime factors of n (for torsion order computation).
/// Returns sorted unique primes. Operates on u32 — no allocation-heavy bigint.
fn prime_factors(mut n: u32) -> Vec<u32> {
    if n <= 1 { return vec![]; }
    let mut factors = Vec::new();
    let mut d = 2u32;
    while d * d <= n {
        if n % d == 0 {
            factors.push(d);
            while n % d == 0 { n /= d; }
        }
        d += 1;
    }
    if n > 1 { factors.push(n); }
    factors
}

/// Build a refractive lens from the node's Δ_k.
///
/// Extracts torsion orders from the prime factorization of each independent
/// entry's numerator and denominator (reduced form). The antisymmetric
/// structure (A.2: D_ij = -D_ji) means the set of unique |D_ij| values
/// defines the node's rotational geometry. Their prime factors are the
/// torsion orders — the cyclic groups Z/pZ that the node's internal
/// structure decomposes into.
///
/// The relational weights carry the sign and magnitude of each entry,
/// determining how each torsion channel biases the observation.
pub fn build_refractive_lens(delta_k: &crate::engine::Delta) -> RefractiveLens {
    let mut torsion_orders: Vec<u32> = Vec::new();
    let mut relational_weights: Vec<Q> = Vec::new();

    for i in 0..delta_k.dim {
        for j in (i + 1)..delta_k.dim {
            for l in 0..delta_k.entries[i][j].len() {
                let entry = &delta_k.entries[i][j][l];
                if entry.is_zero() { continue; }

                // Reduced fraction — extract numerator and denominator as u32
                let n_i64: i64 = entry.numer().try_into().unwrap_or(1i64);
                let d_i64: i64 = entry.denom().try_into().unwrap_or(1i64);
                let numer_abs: u32 = (n_i64.unsigned_abs() as u32).max(1);
                let denom_abs: u32 = (d_i64.unsigned_abs() as u32).max(1);

                // Prime factors of both define the cyclic group structure
                for p in prime_factors(numer_abs) {
                    if !torsion_orders.contains(&p) {
                        torsion_orders.push(p);
                    }
                }
                for p in prime_factors(denom_abs) {
                    if !torsion_orders.contains(&p) {
                        torsion_orders.push(p);
                    }
                }

                relational_weights.push(entry.clone());
            }
        }
    }

    // Ensure at least one torsion order — 1 resonates uniformly (no spatial bias)
    if torsion_orders.is_empty() {
        torsion_orders.push(1);
    }

    torsion_orders.sort();

    RefractiveLens { torsion_orders, relational_weights }
}

impl RefractiveLens {
    /// Compute the raw resonance at grid position (row, col) from the
    /// torsion spectrum. Each torsion order t contributes a continuous
    /// value based on the 2D distance to the nearest resonance point.
    ///
    /// At exact multiples of t: maximum positive resonance.
    /// At anti-resonance (midpoint between multiples): maximum negative.
    /// The transition is linear — no boolean gates, no thresholds.
    ///
    /// Returns the raw (unnormalized) resonance. The caller normalizes
    /// per-grid: center by subtracting grid mean (removes constant offset
    /// from large torsion orders that can't complete a period in small
    /// grids), then scale the spatial variation to [-2, +2].
    pub fn raw_resonance(&self, row: usize, col: usize) -> i64 {
        let mut bias = 0i64;

        for (idx, &t) in self.torsion_orders.iter().enumerate() {
            if t <= 1 { continue; }
            let t_us = t as usize;

            // Distance to nearest resonance point in each dimension
            let r_mod = row % t_us;
            let r_dist = r_mod.min(t_us - r_mod) as i64;
            let c_mod = col % t_us;
            let c_dist = c_mod.min(t_us - c_mod) as i64;

            // Resonance: positive at multiples, negative at anti-resonance.
            // Range per order: [-half_t, +half_t]
            let half_t = (t as i64 + 1) / 2;
            let resonance = half_t - r_dist - c_dist;

            // Scale by relational weight direction
            let channel_bias = if idx < self.relational_weights.len() {
                let w = &self.relational_weights[idx];
                if w < &Q::zero() {
                    -resonance
                } else {
                    resonance
                }
            } else {
                resonance
            };

            bias += channel_bias;
        }

        bias
    }

    /// Compute normalized torsion biases for a full grid.
    ///
    /// Three steps, no boolean gates:
    /// 1. Compute raw resonance at every cell
    /// 2. Subtract the grid mean — removes constant offset from large
    ///    torsion orders that are bigger than the grid (they contribute
    ///    nearly uniform bias, which shifts all values equally and has
    ///    no effect on the value mapping). What remains is the spatial
    ///    variation from small orders that complete at least one period.
    /// 3. Normalize the variation to [-2, +2] — preserves observation
    ///    value semantics (ARC values 0-9, shift of ±2 keeps values
    ///    in a meaningful range)
    ///
    /// Returns per-cell i64 biases indexed by cell position (row-major).
    pub fn grid_biases(&self, rows: usize, cols: usize) -> Vec<i64> {
        let n = rows * cols;
        if n == 0 { return vec![]; }

        // Step 1: raw resonances
        let raw: Vec<i64> = (0..n)
            .map(|idx| self.raw_resonance(idx / cols, idx % cols))
            .collect();

        // Step 2: center — subtract mean to isolate spatial variation
        let sum: i64 = raw.iter().sum();
        let mean = sum / n as i64;
        let centered: Vec<i64> = raw.iter().map(|&r| r - mean).collect();

        // Step 3: normalize to [-2, +2]
        let max_abs = centered.iter().map(|b| b.abs()).max().unwrap_or(1).max(1);
        centered.iter().map(|&b| (b * 2) / max_abs).collect()
    }

    /// Compute the mean absolute resonance strength across all cells
    /// in a grid. Returns Q in [0, 1] — the lens's refractive index
    /// for this observation size. Higher = more spatial differentiation.
    pub fn refractive_index(&self, rows: usize, cols: usize) -> Q {
        if rows == 0 || cols == 0 { return Q::zero(); }
        let biases = self.grid_biases(rows, cols);
        let n = biases.len().max(1) as i64;
        let total: i64 = biases.iter().map(|b| b.abs()).sum();
        // Max possible per cell is 2 (from grid_biases normalization)
        Q::new(BigInt::from(total), BigInt::from(n * 2))
    }
}

/// Cognize with knowledge and algebraic lens.
///
/// The node's algebraic state (lens_delta) IS the refraction. The observation
/// passes through the lens via dimensionless torsion resonance — not direct
/// cell overlap. Different nodes with different Δ_k produce different torsion
/// spectra, which modulate different spatial periodicities in the observation.
/// This is where torsion originates: algebraic diversity in the mesh.
///
/// When prior_knowledge is Some, the comprehension engine is informed by
/// the mesh's accumulated understanding of this orbit.
///
/// When lens_delta is Some, the observation is refracted through the node's
/// torsion spectrum. The refraction modulates training pair inputs at every
/// cell — cells at torsion resonance points are biased positively, cells at
/// anti-resonance are biased negatively. The output is never modified.
pub fn cognize_with_knowledge(
    training_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rcf_identity: Option<&[u8; 32]>,
    prior_knowledge: Option<&crate::thinking::ComprehensionRecord>,
    lens_delta: Option<&crate::engine::Delta>,
) -> Cognition {
    cognize_with_membrane(training_pairs, test_input, rcf_identity, prior_knowledge, lens_delta, None, &[])
}

/// D.MEMBRANE.V.1 — Cognize with membrane gauge connection.
///
/// The membrane's consensus T (from the meta-Delta's coboundary) constrains
/// the primary node's escalation. The witness rotates its local frame into alignment
/// with the membrane's global holonomy. Each cycle is gauge cooling —
/// reducing C(meta_delta) toward zero.
///
/// membrane_t: the consensus entity vector from the membrane's meta-Delta.
/// When present, the escalation's congruent core is informed by the membrane.
pub fn cognize_with_membrane(
    training_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rcf_identity: Option<&[u8; 32]>,
    prior_knowledge: Option<&crate::thinking::ComprehensionRecord>,
    lens_delta: Option<&crate::engine::Delta>,
    membrane_t: Option<&crate::engine::Delta>,
    harmonics: &[crate::engine::Q],
) -> Cognition {
    cognize_with_membrane_and_transmutation(
        training_pairs, test_input, rcf_identity, prior_knowledge,
        lens_delta, membrane_t, harmonics, None, &[], &[], &[], &[] as &[crate::membrane::SpatialCochain], &[],
    )
}

/// D.VISION.LOOP — Cognize with membrane transmutation prior.
///
/// The membrane's crystallized transmutation (quality, torsion_order)
/// feeds back into vision. The primary node perceives with both its innate
/// state record AND the membrane's accumulated knowledge. This closes the
/// self-learning loop: perceive → compound → crystallize → perceive.
///
/// L3 Holonomic: `genomic_torsion` carries crystallized torsion markers
/// from the state record. These are permanent symmetry alleles — the primary node
/// is structurally tuned to perceive these symmetry classes.
pub fn cognize_with_membrane_and_transmutation(
    training_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    rcf_identity: Option<&[u8; 32]>,
    prior_knowledge: Option<&crate::thinking::ComprehensionRecord>,
    lens_delta: Option<&crate::engine::Delta>,
    membrane_t: Option<&crate::engine::Delta>,
    harmonics: &[crate::engine::Q],
    membrane_transmutation: Option<(crate::engine::Q, usize)>,
    genomic_torsion: &[(u16, crate::engine::Q)],
    genomic_value_cocycles: &[(i16, i16, crate::engine::Q)],
    membrane_cocycles: &[(i64, i64, crate::engine::Q)],
    membrane_spatial_cochains: &[crate::membrane::SpatialCochain],
    composed_operators: &[crate::engine::ComposedOperator],
) -> Cognition {
    let n = if !training_pairs.is_empty() { training_pairs[0].0.len() } else { test_input.len() };

    // Per-level torsion and cocycle from nested peel — function-scoped for Cognition construction
    let mut peel_value_torsion: u16 = 1;
    let mut peel_object_torsion: u16 = 1;
    let mut peel_full_torsion: u16 = 1;
    let mut peel_value_cocycle: i64 = 0;
    let mut peel_object_cocycle: i64 = 0;

    // ── Step 1: Observation — raw data ──
    let mut gc = 1usize;
    let mut best_cols = 1usize;
    while gc * gc <= n { if n % gc == 0 { best_cols = gc; } gc += 1; }
    let cols = best_cols;
    let rows = n / cols;

    let values = if !training_pairs.is_empty() {
        training_pairs[0].0.clone()
    } else {
        test_input.to_vec()
    };

    // ── Step 1b: Refractive lens — dimensionless algebraic resonance ──
    let refractive_lens: Option<RefractiveLens> = lens_delta.map(build_refractive_lens);

    // ── Step 2: Comprehension FIRST — before encoding ──
    // Comprehension measures the observation's character with O(n) tools
    // (hearing, sparsity). The character determines WHAT gets encoded
    // as relational entities. Cell-level encoding (O(n²)) is only
    // appropriate when n is small enough for the algebra to process.
    // For larger observations, the natural entities are value categories
    // or spatial clusters — not individual cells.

    // Hearing is cheap (O(n)) — always run it first for comprehension
    let hearing = compute_value_spectrum(&values);

    let background_val = if hearing.has_background { hearing.background_value } else { -1 };
    let foreground_cells = if hearing.has_background {
        hearing.total_cells - hearing.dominant_count
    } else {
        hearing.total_cells
    };
    let total_cells = hearing.total_cells;
    let sparsity = if total_cells > 0 {
        Q::new(BigInt::from(foreground_cells as i64), BigInt::from(total_cells as i64))
    } else {
        Q::zero()
    };

    // Sparse threshold: less than 1/4 foreground → sparse field
    let _sparse = foreground_cells * 4 < total_cells && total_cells > 4;
    // Dense threshold: more than 3/4 foreground → dense field
    // Size change?
    let dimensional = !training_pairs.is_empty()
        && training_pairs[0].0.len() != training_pairs[0].1.len();

    // Select tools based on comprehension + prior knowledge
    // Knowledge refines the engine: if the library says "this orbit needed
    // inter-object derivation," activate touch regardless of density.
    let knowledge_says_objects = prior_knowledge
        .map(|k| k.object_count >= 2 || k.semantic_intent == "relate" || k.semantic_intent == "conjugate")
        .unwrap_or(false);
    let knowledge_says_vision = prior_knowledge
        .map(|k| k.cognitive_path == "vision_derived")
        .unwrap_or(false);

    // ── Natural encoding level — measured, not prescriptive ──
    // The entity measures where the observation's complexity naturally sits.
    // This does NOT gate senses. Senses compound at all levels.
    // The natural_level informs the mesh about where comprehension succeeded
    // or where it lost coherence — it's a measurement, not a constraint.
    let sparse = sparsity < Q::new(BigInt::from(1), BigInt::from(4));
    let _dense = sparsity > Q::new(BigInt::from(3), BigInt::from(4));

    // Prior knowledge from the mesh can shift the encoding level.
    // If a peer discovered this orbit resolves at object level, this node
    // starts there. Different knowledge → different encoding → different
    // derived output → genuine torsion between entity perspectives.
    let knowledge_says_encoding = prior_knowledge
        .map(|k| k.cognitive_path)
        .unwrap_or("auto");

    // NaturalLevel: comprehension measures WHERE the observation's relational
    // structure naturally lives. The question is not "is it sparse" — it's
    // "are there fewer meaningful entities than raw cells?"
    //
    // Value categories ARE the meaningful entities. When unique_count << n,
    // the observation's relational structure is between categories, not between
    // individual cells. A 441-cell grid with 7 values has 7 meaningful entities.
    // Encoding 441 cells squares the problem. Encoding 7 categories doesn't.
    //
    // Cell level is only appropriate when the cell count IS the entity count:
    // small observations where the cells themselves are the relational entities.
    let natural_level = if dimensional {
        NaturalLevel::Dimensional
    } else if knowledge_says_encoding == "evolved" || knowledge_says_objects {
        NaturalLevel::Object
    } else if sparse && foreground_cells > 0 {
        NaturalLevel::Object
    } else if hearing.unique_count < n && n > hearing.unique_count * hearing.unique_count {
        // The observation has fewer value categories than cells, and n² would be
        // much larger than unique² — encode at category level.
        // This is not a threshold. It's the observation measuring itself:
        // "my relational structure has unique_count entities, not n entities."
        NaturalLevel::Object
    } else {
        NaturalLevel::Cell
    };

    let tools = SensoryTools {
        // Vision: relevant for non-sparse fields with grid structure.
        // Senses are not gated by encoding level — they compound.
        vision: if (!sparse && rows > 1 && cols > 1) || knowledge_says_vision { Q::one() } else { Q::zero() },
        hearing: Q::one(),
        touch: if foreground_cells > 0 || knowledge_says_objects { Q::one() } else { Q::zero() },
        refraction: Q::one(),
        quotient: Q::zero(),
    };

    let dimensional_ratio = if !training_pairs.is_empty() && training_pairs[0].0.len() > 0 {
        Q::new(BigInt::from(training_pairs[0].1.len() as i64), BigInt::from(training_pairs[0].0.len() as i64))
    } else { Q::zero() };
    let comprehension = Comprehension {
        foreground_cells, total_cells, sparsity,
        dimensional_ratio, tools, natural_level,
    };

    // ── Step 2b: Encode at the natural level — comprehension drives encoding ──
    // The Delta encodes the observation's relational structure at the level
    // comprehension measured. Cell level for small observations. Value-category
    // level for larger ones where n² would exceed the algebra's capacity.
    // The encoding level is not a threshold — it follows from the observation's
    // own measured character: hearing (value categories), touch (clusters),
    // and the NaturalLevel that comprehension derived from those measurements.
    let (delta, obs_n, obs_m) = match natural_level {
        NaturalLevel::Cell => {
            // Cell-level encoding. Measure the fuse, not the blast.
            // d = n(n-1)/2 × m. d_max = 1500 (metabolic horizon of a 192MB primary node).
            // The entity selects the richest spectral dimension it can afford.
            // No boolean gates — the horizon IS the selection.
            const D_MAX: usize = 1500;
            let half_n = n * n.saturating_sub(1) / 2;
            [4usize, 1].iter()
                .find(|&&m| half_n * m <= D_MAX)
                .map(|&m| match m {
                    4 => (encode_grid_objects(&values, rows, cols), n, 4),
                    _ => {
                        let entities: Vec<Vec<Q>> = values.iter()
                            .map(|&v| vec![Q::from(BigInt::from(v))])
                            .collect();
                        (encode_relational(&entities), n, m)
                    }
                })
                .unwrap_or_else(|| (Delta::zero(1, 1), 1, 1))
        }
        NaturalLevel::Object | NaturalLevel::Dimensional => {
            // Value-category level: each unique value is an entity.
            // Entity coordinates: (value, mean_row, mean_col) — m = 3.
            // n = unique_count (typically 3-10). O(n²) is trivial.
            // The spatial arrangement is preserved through mean position.
            // Vec with find — Core Design Law II. Delta IS the map.
            let mut categories: Vec<(i64, i64, i64, i64)> = Vec::new(); // (value, count, sum_r, sum_c)
            for (idx, &v) in values.iter().enumerate() {
                let r = (idx / cols) as i64;
                let c = (idx % cols) as i64;
                match categories.iter_mut().find(|(val, _, _, _)| *val == v) {
                    Some(entry) => { entry.1 += 1; entry.2 += r; entry.3 += c; }
                    None => categories.push((v, 1, r, c)),
                }
            }
            categories.sort_by_key(|(v, _, _, _)| *v);
            let entities: Vec<Vec<Q>> = categories.iter().map(|&(v, count, sum_r, sum_c)| {
                vec![
                    Q::new(BigInt::from(v), BigInt::from(1)),
                    Q::new(BigInt::from(sum_r), BigInt::from(count.max(1))),
                    Q::new(BigInt::from(sum_c), BigInt::from(count.max(1))),
                ]
            }).collect();
            let entity_n = entities.len();
            let d = encode_relational(&entities);
            (d, entity_n, 3)
        }
    };

    let observation = Observation {
        delta: delta.clone(),
        n: obs_n, m: obs_m,
        values: values.clone(),
        rows, cols,
    };

    // ── Step 3: Targeted sensing — hearing → vision → touch → refraction ──
    // Hearing is already computed (step 2). Vision next — see the transformation.
    // If vision fully resolves, return without touch (lighter before heavier).

    // Vision: see the transformation between input and output
    // This is transliminal — looks at the RELATIONSHIP, not input symmetry.
    let same_size = !training_pairs.is_empty()
        && training_pairs.iter().all(|(i, o)| i.len() == o.len());
    // Vision: see the transformation (transliminal).
    // If vision resolves, store the result. The full sensory compound still
    // runs — senses compound, understanding doesn't skip sensing.
    // The vision result feeds into perceive_with_compound as prior knowledge.
    // Vision: see_transformation — returns None after VIII.4 purge.
    // Spatial+value composition now handled by escalation through T.
    let vision_resolved = if same_size && rows > 0 && cols > 0 && rows * cols == n
        && !training_pairs.is_empty() && n <= 900
    {
        see_transformation(training_pairs, rows, cols)
    } else {
        None
    };

    // ── Dimensional escalation: category → cluster → cell ──
    // If vision didn't resolve, try algebraic escalation through the
    // transformation cocycle at increasing dimensional levels.
    // Each level preserves the congruent core from below.
    // Escalate when we have test input that differs from training —
    // when test_input equals training input, the caller wants the full
    // sensory compound (congruence, touch, refraction), not a shortcut.
    let test_differs = !test_input.is_empty()
        && (test_input.len() != training_pairs[0].0.len()
            || test_input.iter().zip(training_pairs[0].0.iter()).any(|(a, b)| a != b));
    if vision_resolved.is_none() && same_size && rows > 0 && cols > 0 && rows * cols == n
        && !training_pairs.is_empty() && test_differs
    {
        match crate::thinking::escalate_with_membrane(training_pairs, test_input, rows, cols, membrane_t) {
            crate::thinking::EscalationResult::Resolved(ref tr) => {
                let derived_output = tr.derived_output.clone().unwrap_or_default();
                let level = tr.resolved_level;
                let orbit_prefix = if let Some(rcf) = rcf_identity {
                    [rcf[0], rcf[1], rcf[2], rcf[3]]
                } else {
                    let rcf = crate::engine::compute_rcf_hash(&delta);
                    [rcf[0], rcf[1], rcf[2], rcf[3]]
                };

                let hearing_for_return = compute_value_spectrum(&values);
                return Cognition {
                    observation,
                    comprehension,
                    senses: SensoryModel {
                        vision: None,
                        hearing: hearing_for_return,
                        touch: AdjacencyStructure {
                            same_adjacencies: 0, diff_adjacencies: 0,
                            cohesion: Q::zero(), component_count: 0,
                            per_cell_cohesion: vec![], per_cell_stabilizer: vec![],
                            clusters: vec![],
                        },
                        refraction: vec![],
                        soundness: SoundnessSpectrum {
                            value_identity: Q::zero(), spatial_position: Q::zero(),
                            adjacency_coherence: Q::zero(), cluster_structure: Q::zero(),
                            symmetry_order: Q::zero(), boundary_behavior: Q::zero(),
                            periodicity: Q::zero(), value_transition: Q::zero(),
                            dimensional_bridge: Q::zero(), cross_pair_consistency: Q::zero(),
                            residual_structure: Q::zero(),
                        },
                    },
                    inquiry: EchelonInquiry {
                        orientation: Orientation::I,
                        torsion_query: false, torsion_order: 0,
                        consistency_query: false, residual_query: false,
                        object_count: 0,
                        congruence: SensoryCongruence {
                            symmetry_broken: 0, symmetry_preserved: 0,
                            vision_touch_congruence: Q::one(),
                            touch_refraction_congruence: Q::one(),
                            transmutation_magnitude: Q::zero(),
                        },
                        routed_level: level,
                        capacity: "escalation",
                    },
                    bridge: None,
                    perception: Perception {
                        derived_output,
                        coherence: Q::one(),
                        class: PerceptionClass::Recognition,
                        rule: crate::thinking::FactoredRule::NoRule,
                        empirical_basis: training_pairs.len(),
                        resolution: None,
                        composition_depth: 0,
                        symmetry: None,
                        generator_source: None,
                    },
                    residual_topology: None,
                    knowledge: Knowledge {
                        orbit_prefix,
                        symmetry_order: 0,
                        torsion_spectrum: vec![],
                        path: CognitionPath::Evolved { composition_depth: 0 },
                        derived_output: vec![],
                        coherence: Q::one(),
                    },
                    // D.MEMBRANE.T.1: Carry the best T Delta for membrane compound
                    transformation_t: tr.levels.last().map(|l| l.t_delta.clone()),
                    transformation_level: Some(level),
                    transmutation: None, // escalation path — no vision measurement
                    compositions: vec![],
                    value_torsion: 1, object_torsion: 1, full_torsion: 1,
                    value_cocycle: 0, object_cocycle: 0,
                };
            }
            _ => {} // Partial or Unresolved — fall through to full pipeline.
               // The holonomic path (escalation) resolved what it could.
               // The luminal path (peel_manifold) navigates the residual.
        }
    }

    // Vision: compute symmetry group for congruence measurements
    // (only needed when see_transformation AND escalation didn't resolve)
    //
    // D.VISION.LOOP: When the membrane holds a crystallized transmutation,
    // it compounds with the state record harmonics. The primary node perceives with
    // its innate aperture PLUS the membrane's accumulated knowledge.
    // The membrane prior amplifies spatial harmonics in the direction of
    // the crystallized operator — the primary node focuses for what the
    // membrane already knows. This IS the self-learning loop.
    let vision_harmonics: Vec<crate::engine::Q> = if let Some((ref quality, _order)) = membrane_transmutation {
        // Membrane prior: amplify spatial harmonics (h1, h2) by the
        // crystallized quality. Value harmonic (h0) stays innate.
        // A 93% crystal amplifies spatial by 93%. A 50% crystal by 50%.
        // This is gauge cooling of the aperture toward the membrane's focus.
        let h0 = harmonics.get(0).cloned().unwrap_or_else(|| crate::engine::Q::one());
        let h1 = harmonics.get(1).cloned().unwrap_or_else(|| crate::engine::Q::one());
        let h2 = harmonics.get(2).cloned().unwrap_or_else(|| crate::engine::Q::one());
        let amplified_h1 = &h1 + &(&h1 * quality);
        let amplified_h2 = &h2 + &(&h2 * quality);
        let mut vh = vec![h0, amplified_h1, amplified_h2];
        // Carry remaining harmonics unchanged
        for i in 3..harmonics.len() {
            vh.push(harmonics[i].clone());
        }
        vh
    } else {
        harmonics.to_vec()
    };

    let vision = if comprehension.tools.vision > Q::zero() {
        let mut sym = compute_symmetry_group(&values, rows, cols);
        // Measure transmutation: R_g(φ) = ‖W_k · (φ(source) - target)‖
        // State-record weighted — each primary node perceives through its own aperture,
        // now compounded with the membrane's crystallized prior.
        if !training_pairs.is_empty() && same_size {
            measure_transmutation(&mut sym, &training_pairs[0].0, &training_pairs[0].1,
                                  rows, cols, &vision_harmonics);
        }
        Some(sym)
    } else {
        None
    };

    // ── D.VISION.PROJECT — Transmutation as generator candidate ──
    // The membrane's crystallized transmutation enters peel_manifold as a
    // generator weighted by its Q. No boolean gate. No threshold. No early return.
    // The transmutation quality IS the weight. C selects across all generators.
    // A 93.5% transmutation competes against category and cluster generators.
    // A 10% transmutation competes too — and loses on C. The gradient decides.
    //
    // The transmutation data (permutation + value map + quality) is prepared
    // here and passed into peel_manifold via SenseData.
    let mut transmutation_candidates: Vec<(Vec<usize>, Q)> = if let Some(ref sym) = vision {
        // For each symmetry element, prepare (permutation, transmutation_quality).
        // Both forward and inverse permutations are candidates.
        let grid_n = n;
        let mut candidates = Vec::new();
        for elem in &sym.elements {
            for mat in [&elem.operator.matrix, &elem.operator.matrix_inv] {
                let perm: Vec<usize> = (0..grid_n).map(|i| {
                    if i < mat.len() {
                        mat[i].iter().enumerate()
                            .find(|(_, v)| !v.is_zero())
                            .map(|(j, _)| j)
                            .unwrap_or(i)
                    } else { i }
                }).collect();
                candidates.push((perm, elem.transmutation_residual.clone()));
            }
        }
        candidates
    } else {
        vec![]
    };

    // ── L2 Transluminal: Membrane consensus as symmetry-matched candidate ──
    // The membrane T-Delta flows through the lens as a Delta (via combined_delta
    // in main.rs). Here we additionally match crystallized transmutation signals
    // against vision symmetry elements for the spatial component of φ=(π, f_π).
    // The membrane provides the spectral dimension through the lens Delta.
    // Vision provides the spatial dimension through symmetry elements.
    // They compose — they don't compete.
    if let Some((ref membrane_quality, membrane_order)) = membrane_transmutation {
        if let Some(ref sym) = vision {
            for elem in &sym.elements {
                if elem.torsion_order == membrane_order {
                    let grid_n = n;
                    for mat in [&elem.operator.matrix, &elem.operator.matrix_inv] {
                        let perm: Vec<usize> = (0..grid_n).map(|i| {
                            if i < mat.len() {
                                mat[i].iter().enumerate()
                                    .find(|(_, v)| !v.is_zero())
                                    .map(|(j, _)| j)
                                    .unwrap_or(i)
                            } else { i }
                        }).collect();
                        // Use the MEMBRANE's quality as the residual, not this
                        // primary node's local measurement. The consensus carries the
                        // mesh's collective confidence. Lower residual = stronger candidate.
                        // Invert quality to residual: high quality → low residual.
                        let consensus_residual = &Q::one() - membrane_quality;
                        transmutation_candidates.push((perm, consensus_residual));
                    }
                    break; // One matching element is sufficient
                }
            }
        }
    }

    // ── L3 Holonomic: Genomic torsion markers as permanent candidates ──
    // The state record carries crystallized symmetry alleles. These are the primary node's
    // hard-coded perception — it is structurally tuned to these symmetry classes.
    // For each genomic marker, inject the matching symmetry element with the
    // state record's crystallized quality. This is O(1) recall, not search.
    if !genomic_torsion.is_empty() {
        if let Some(ref sym) = vision {
            for &(marker_order, ref marker_quality) in genomic_torsion {
                for elem in &sym.elements {
                    if elem.torsion_order == marker_order as usize {
                        let grid_n = n;
                        for mat in [&elem.operator.matrix, &elem.operator.matrix_inv] {
                            let perm: Vec<usize> = (0..grid_n).map(|i| {
                                if i < mat.len() {
                                    mat[i].iter().enumerate()
                                        .find(|(_, v)| !v.is_zero())
                                        .map(|(j, _)| j)
                                        .unwrap_or(i)
                                } else { i }
                            }).collect();
                            // Genomic quality → residual (inverted)
                            let genomic_residual = &Q::one() - marker_quality;
                            transmutation_candidates.push((perm, genomic_residual));
                        }
                        break;
                    }
                }
            }
        }
    }

    // Touch: only if foreground exists AND vision didn't resolve
    let touch = if comprehension.tools.touch > Q::zero() {
        compute_adjacency_structure(&values, rows, cols)
    } else {
        AdjacencyStructure {
            same_adjacencies: 0, diff_adjacencies: 0,
            cohesion: Q::zero(), component_count: 0,
            per_cell_cohesion: vec![], per_cell_stabilizer: vec![],
            clusters: vec![],
        }
    };

    // Attach stabilizers: only if both vision and touch are active
    let mut touch = touch;
    if let Some(ref sym) = vision {
        attach_stabilizers(&mut touch, sym);
    }

    // Object detection from touch — measure counts before moving touch
    let object_count = touch.clusters.iter()
        .filter(|c| c.value != background_val && c.cell_indices.len() > 1)
        .count();
    let high_cohesion = touch.cohesion > Q::new(BigInt::from(1), BigInt::from(2));
    // Count anchored objects (stabilizer > 1) for vision-touch congruence
    let anchored_object_count = touch.clusters.iter()
        .filter(|c| c.value != background_val && c.cell_indices.len() > 1 && c.stabilizer_order > 1)
        .count();

    // ── D.VISION.LOCAL — Per-cluster transmutation measurement ──
    // Global symmetry operators (D4 + shifts) cover whole-grid transmutations.
    // Most puzzles transmute at the OBJECT level — each cluster independently.
    // For each foreground source cluster, match to a target cluster, compute
    // the local symmetry group and measure local transmutation R_g(φ).
    // Embed local permutations into grid-sized candidates. C selects.
    //
    // This is perception — we measure what each object transmuted through.
    // We do not compute deltas. We do not apply operators.
    if object_count >= 2 && same_size && !training_pairs.is_empty() {
        let target_adj = compute_adjacency_structure(&training_pairs[0].1, rows, cols);
        let source_fg: Vec<&CohesionCluster> = touch.clusters.iter()
            .filter(|c| c.value != background_val && c.cell_indices.len() > 1)
            .collect();
        let target_fg: Vec<&CohesionCluster> = target_adj.clusters.iter()
            .filter(|c| c.cell_indices.len() > 1)
            .collect();

        // Match source clusters to target clusters by bbox center proximity.
        // Each source cluster finds its nearest target cluster. No boolean gate —
        // every match produces a measurement. Quality determines relevance.
        for src_cl in &source_fg {
            let src_center_r = (src_cl.bbox.0 + src_cl.bbox.2) as i64;
            let src_center_c = (src_cl.bbox.1 + src_cl.bbox.3) as i64;

            let mut best_dist = i64::MAX;
            let mut best_tgt: Option<&CohesionCluster> = None;
            for tgt_cl in &target_fg {
                let tgt_center_r = (tgt_cl.bbox.0 + tgt_cl.bbox.2) as i64;
                let tgt_center_c = (tgt_cl.bbox.1 + tgt_cl.bbox.3) as i64;
                let dist = (src_center_r - tgt_center_r).abs() + (src_center_c - tgt_center_c).abs();
                if dist < best_dist {
                    best_dist = dist;
                    best_tgt = Some(tgt_cl);
                }
            }

            let tgt_cl = match best_tgt {
                Some(t) => t,
                None => continue,
            };

            // Extract cluster subgrids from their bounding boxes.
            let s_rows = src_cl.bbox.2 - src_cl.bbox.0 + 1;
            let s_cols = src_cl.bbox.3 - src_cl.bbox.1 + 1;
            let t_rows = tgt_cl.bbox.2 - tgt_cl.bbox.0 + 1;
            let t_cols = tgt_cl.bbox.3 - tgt_cl.bbox.1 + 1;

            // Same local dimensions required for symmetry measurement
            if s_rows != t_rows || s_cols != t_cols || s_rows == 0 || s_cols == 0 {
                continue;
            }

            let local_n = s_rows * s_cols;
            let mut src_sub = vec![0i64; local_n];
            let mut tgt_sub = vec![0i64; local_n];
            for lr in 0..s_rows {
                for lc in 0..s_cols {
                    let src_idx = (src_cl.bbox.0 + lr) * cols + (src_cl.bbox.1 + lc);
                    let tgt_idx = (tgt_cl.bbox.0 + lr) * cols + (tgt_cl.bbox.1 + lc);
                    let local_idx = lr * s_cols + lc;
                    if src_idx < training_pairs[0].0.len() {
                        src_sub[local_idx] = training_pairs[0].0[src_idx];
                    }
                    if tgt_idx < training_pairs[0].1.len() {
                        tgt_sub[local_idx] = training_pairs[0].1[tgt_idx];
                    }
                }
            }

            // Compute local symmetry group + transmutation measurement
            let mut local_sym = compute_symmetry_group(&src_sub, s_rows, s_cols);
            if local_sym.elements.is_empty() { continue; }
            measure_transmutation(&mut local_sym, &src_sub, &tgt_sub,
                                  s_rows, s_cols, &vision_harmonics);

            // Embed local permutations into grid-level candidates.
            // Identity outside the source bounding box. Local permutation inside.
            // Each local element produces a grid-level candidate.
            let grid_n = rows * cols;
            for elem in &local_sym.elements {
                for mat in [&elem.operator.matrix, &elem.operator.matrix_inv] {
                    // Extract local permutation from the operator matrix
                    let local_perm: Vec<usize> = (0..local_n).map(|i| {
                        if i < mat.len() {
                            mat[i].iter().enumerate()
                                .find(|(_, v)| !v.is_zero())
                                .map(|(j, _)| j)
                                .unwrap_or(i)
                        } else { i }
                    }).collect();

                    // Embed into grid-level permutation
                    let mut grid_perm: Vec<usize> = (0..grid_n).collect();
                    for lr in 0..s_rows {
                        for lc in 0..s_cols {
                            let local_src = lr * s_cols + lc;
                            let local_dst = if local_src < local_perm.len() {
                                local_perm[local_src]
                            } else { local_src };
                            let dst_lr = local_dst / s_cols;
                            let dst_lc = local_dst % s_cols;
                            // Map local coords to grid coords via target bbox
                            // (permutation moves source bbox content to target bbox position)
                            let grid_src = (src_cl.bbox.0 + lr) * cols + (src_cl.bbox.1 + lc);
                            let grid_dst = (tgt_cl.bbox.0 + dst_lr) * cols + (tgt_cl.bbox.1 + dst_lc);
                            if grid_src < grid_n && grid_dst < grid_n {
                                grid_perm[grid_src] = grid_dst;
                            }
                        }
                    }
                    transmutation_candidates.push((grid_perm, elem.transmutation_residual.clone()));
                }
            }
        }
    }

    // Refraction: only if touch found ≥2 clusters and training pairs exist
    let refraction = if object_count >= 2 && !training_pairs.is_empty() {
        measure_refraction(
            &touch,
            &training_pairs[0].0,
            &training_pairs[0].1,
            rows, cols,
        )
    } else {
        vec![]
    };

    // Symmetry quotient: only if vision was active and meaningful
    let (symmetry_broken, symmetry_preserved) = if vision.as_ref().map(|s| s.order > 0).unwrap_or(false)
        && !training_pairs.is_empty()
        && training_pairs[0].0.len() == training_pairs[0].1.len()
    {
        let (_, _, broken, preserved) = symmetry_quotient(
            &training_pairs[0].0, &training_pairs[0].1, rows, cols,
        );
        (broken, preserved)
    } else {
        (0, 0)
    };

    let senses = SensoryModel {
        vision: vision.clone(),
        hearing,
        touch,
        refraction,
        // Soundness spectrum placeholder — filled after all measurements complete
        soundness: SoundnessSpectrum {
            value_identity: Q::zero(), spatial_position: Q::zero(),
            adjacency_coherence: Q::zero(), cluster_structure: Q::zero(),
            symmetry_order: Q::zero(), boundary_behavior: Q::zero(),
            periodicity: Q::zero(), value_transition: Q::zero(),
            dimensional_bridge: Q::zero(), cross_pair_consistency: Q::zero(),
            residual_structure: Q::zero(),
        },
    };

    // For backward compatibility
    let symmetry = vision.clone();

    // ── Step 4: Sensory congruence → orientation ──
    // Only comprehended senses participate. No garbage in the compound.
    let torsion_query = symmetry.as_ref().map(|s| s.order > 0).unwrap_or(false);
    let torsion_order = symmetry.as_ref()
        .and_then(|s| s.torsion_spectrum.first().map(|&(o, _)| o))
        .unwrap_or(0);

    // VIII.4: consistency_query no longer uses HashMap value factoring.
    // Cross-pair consistency is measured through T in escalation.
    let consistency_query = false;

    // Congruence only between ACTIVE senses — don't compare garbage
    let vision_touch_congruence = if torsion_query && object_count >= 2 {
        if object_count > 0 {
            Q::new(BigInt::from(anchored_object_count as i64), BigInt::from(object_count as i64))
        } else {
            Q::one()
        }
    } else {
        Q::one() // no contradiction possible when one sense is inactive
    };

    let touch_refraction_congruence = if object_count >= 2 && !senses.refraction.is_empty() {
        let transparent_count = senses.refraction.iter().filter(|r| r.transparent).count();
        if senses.refraction.is_empty() { Q::one() }
        else { Q::new(BigInt::from(transparent_count as i64), BigInt::from(senses.refraction.len() as i64)) }
    } else {
        Q::one()
    };

    let vision_touch_congruent = vision_touch_congruence > Q::new(BigInt::from(1), BigInt::from(2));
    let touch_refraction_congruent = touch_refraction_congruence > Q::new(BigInt::from(1), BigInt::from(2));

    let transmutation_signal =
        (torsion_query && symmetry_broken > 0)
        || !vision_touch_congruent
        || (!touch_refraction_congruent && object_count >= 2);

    let transmutation_magnitude = if transmutation_signal { Q::one() } else { Q::zero() };

    let congruence = SensoryCongruence {
        symmetry_broken,
        symmetry_preserved,
        vision_touch_congruence,
        touch_refraction_congruence,
        transmutation_magnitude,
    };

    // Orientation emerges from comprehended compound
    let (orientation, routed_level, capacity) = if transmutation_signal && symmetry_broken > 0 {
        (Orientation::Me, "asymmetry", "transmute")
    } else if torsion_query && torsion_order >= 2 && vision_touch_congruent {
        (Orientation::We, "vision", "mirror")
    } else if high_cohesion && object_count >= 2 && !touch_refraction_congruent {
        (Orientation::I, "object", "conjugate")
    } else if high_cohesion && object_count >= 2 {
        (Orientation::I, "object", "conjugate")
    } else if consistency_query {
        (Orientation::You, "factoring", "derive")
    } else if transmutation_signal {
        (Orientation::Me, "contradiction", "transmute")
    } else {
        (Orientation::I, "evolution", "evolve")
    };

    // Save congruence values for soundness spectrum (congruence moves into inquiry)
    let sound_layer4 = congruence.vision_touch_congruence.clone();
    let sound_layer6 = congruence.touch_refraction_congruence.clone();

    let inquiry = EchelonInquiry {
        orientation,
        torsion_query,
        torsion_order,
        consistency_query,
        residual_query: false,
        object_count,
        congruence,
        routed_level,
        capacity,
    };

    // ── Step 5: Dimensional Bridge — structural measurement, always computed ──
    let bridge = if !training_pairs.is_empty() {
        let n_in = training_pairs[0].0.len();
        let n_out = training_pairs[0].1.len();

        let mut gc_in = 1usize;
        let mut best_cols_in = 1usize;
        while gc_in * gc_in <= n_in { if n_in % gc_in == 0 { best_cols_in = gc_in; } gc_in += 1; }
        let cols_in = best_cols_in;
        let rows_in = n_in / cols_in.max(1);

        let mut gc_out = 1usize;
        let mut best_cols_out = 1usize;
        while gc_out * gc_out <= n_out { if n_out % gc_out == 0 { best_cols_out = gc_out; } gc_out += 1; }
        let cols_out = best_cols_out;
        let rows_out = n_out / cols_out.max(1);

        let row_ratio = if rows_in > 0 {
            Q::new(BigInt::from(rows_out as i64), BigInt::from(rows_in as i64))
        } else { Q::one() };
        let col_ratio = if cols_in > 0 {
            Q::new(BigInt::from(cols_out as i64), BigInt::from(cols_in as i64))
        } else { Q::one() };

        let class = if n_in == n_out {
            DimensionalClass::Isomorphic
        } else if rows_out >= rows_in && cols_out >= cols_in
            && rows_out % rows_in == 0 && cols_out % cols_in == 0 {
            let rf = rows_out / rows_in;
            let cf = cols_out / cols_in;
            let exponent = if rf == rows_in && cf == cols_in {
                2
            } else if rf > 0 && rows_in > 0 {
                let mut exp = 1usize;
                let mut power = rows_in;
                while power < rows_out && exp < 10 { power *= rows_in; exp += 1; }
                if power == rows_out { exp } else { 1 }
            } else { 1 };
            DimensionalClass::Expansion { row_factor: rf, col_factor: cf, exponent }
        } else if n_out < n_in {
            DimensionalClass::Contraction
        } else {
            DimensionalClass::Anisotropic
        };

        Some(DimensionalBridge {
            input_rows: rows_in, input_cols: cols_in,
            output_rows: rows_out, output_cols: cols_out,
            row_ratio, col_ratio, class,
        })
    } else { None };

    // ── Step 5b: Dimensional comprehension — Kronecker product ──
    // When the bridge says Expansion(n=2), test: is the output the input ⊗ input?
    // Boolean gate: non-zero cell stamps a copy of the input, zero cell stamps zeros.
    // This is self-similar comprehension — the input IS its own operator.
    if let Some(ref b) = bridge {
        if let DimensionalClass::Expansion { row_factor: rf, col_factor: cf, exponent: 2 } = b.class {
            if !training_pairs.is_empty() && rf == b.input_rows && cf == b.input_cols {
                let mut kr_works = true;

                for (inp, out) in training_pairs {
                    let mut expected = vec![0i64; b.output_rows * b.output_cols];
                    for r in 0..b.input_rows {
                        for c in 0..b.input_cols {
                            let cell_val = inp[r * b.input_cols + c];
                            if cell_val != 0 {
                                for br in 0..rf {
                                    for bc in 0..cf {
                                        let out_r = r * rf + br;
                                        let out_c = c * cf + bc;
                                        let out_idx = out_r * b.output_cols + out_c;
                                        if out_idx < expected.len() && br * b.input_cols + bc < inp.len() {
                                            expected[out_idx] = inp[br * b.input_cols + bc];
                                        }
                                    }
                                }
                            }
                        }
                    }
                    for k in 0..expected.len().min(out.len()) {
                        if expected[k] != out[k] { kr_works = false; break; }
                    }
                    if !kr_works { break; }
                }

                if kr_works {
                    // Kronecker understood — derive output for test input
                    let derived_output = if !test_input.is_empty() && test_input.len() == n {
                        let mut result = vec![0i64; b.output_rows * b.output_cols];
                        for r in 0..b.input_rows {
                            for c in 0..b.input_cols {
                                if test_input[r * b.input_cols + c] != 0 {
                                    for br in 0..rf {
                                        for bc in 0..cf {
                                            let out_r = r * rf + br;
                                            let out_c = c * cf + bc;
                                            let out_idx = out_r * b.output_cols + out_c;
                                            if out_idx < result.len() && br * b.input_cols + bc < test_input.len() {
                                                result[out_idx] = test_input[br * b.input_cols + bc];
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        result
                    } else { vec![] };

                    let perception = Perception {
                        derived_output,
                        coherence: Q::one(),
                        class: PerceptionClass::Recognition,
                        rule: crate::thinking::FactoredRule::NoRule,
                        empirical_basis: training_pairs.len(),
                        resolution: None,
                        composition_depth: 0,
                        symmetry: None,
                        generator_source: None,
                    };

                    let orbit_prefix = if let Some(rcf) = rcf_identity {
                        [rcf[0], rcf[1], rcf[2], rcf[3]]
                    } else {
                        let rcf = crate::engine::compute_rcf_hash(&delta);
                        [rcf[0], rcf[1], rcf[2], rcf[3]]
                    };

                    return Cognition {
                        observation,
                        comprehension,
                        senses,
                        inquiry: EchelonInquiry {
                            orientation: Orientation::We,
                            torsion_query: false,
                            torsion_order: 0,
                            consistency_query: false,
                            residual_query: false,
                            object_count: 0,
                            congruence: SensoryCongruence {
                                symmetry_broken: 0, symmetry_preserved: 0,
                                vision_touch_congruence: Q::one(),
                                touch_refraction_congruence: Q::one(),
                                transmutation_magnitude: Q::zero(),
                            },
                            routed_level: "kronecker",
                            capacity: "self_similar",
                        },
                        bridge,
                        perception,
                        residual_topology: None, // Kronecker: exact, no deviation
                        knowledge: Knowledge {
                            orbit_prefix,
                            symmetry_order: 0,
                            torsion_spectrum: vec![],
                            path: CognitionPath::VisionDerived { torsion_order: 2 },
                            derived_output: vec![],
                            coherence: Q::one(),
                        },
                        transformation_t: Some(crate::engine::Delta::zero(1, 1)),
                        transformation_level: Some("identity"),
                        transmutation: None,
                        compositions: vec![],
                        value_torsion: 1, object_torsion: 1, full_torsion: 1,
                        value_cocycle: 0, object_cocycle: 0,
                    };
                }
            }
        }
    }

    // ── Step 5c: Object-level encoding ──
    // When comprehension detects objects, encode at the object level.
    // Each cluster becomes one entity. The same algebra operates —
    // C(Δ), coordinator, resolution — but on 3 entities instead of 441.
    // The displacement between centroids IS a relational coordinate.
    // The value difference IS a relational coordinate.
    //
    // For each training pair: encode input clusters and output clusters
    // as entities, then factor the object-level value vectors.
    // The rule at the object level IS the inter-object relationship.
    //
    // If the compound achieves exact understanding (magnitude=0), return early.
    // If the compound is incomplete, measure the residual topology as a passive
    // observation and fall through to the standard perception path.
    let compound_residual_topology: Option<ResidualTopology> = None;

    // Enter object-level algebra when: objects detected OR knowledge says to.
    // Knowledge-informed natural_level creates genuine torsion between nodes:
    // a node with knowledge="evolved" enters this path even when a node
    // without knowledge does not — producing a different derived output.
    let object_path_trigger = object_count >= 2
        || (comprehension.natural_level == NaturalLevel::Object && !training_pairs.is_empty());

    // VIII.4: Multi-dimensional recursive algebraic refinement removed.
    // Object-level derivation now flows through peel_manifold below.
    // No HashMap factoring. No per-cluster value mapping. Delta IS the map.
    let _ = object_path_trigger; // measured but derivation is through T

    // ── Step 6: Derive understanding — torsion-based refraction ──
    // When a refractive lens is present, the node perceives the observation
    // through its torsion spectrum. Each cell's input is biased by the lens's
    // resonance at that grid position. Cells at torsion multiples get positive
    // bias (amplified perception). Cells at anti-resonance get negative bias
    // (attenuated perception). The output is never modified.
    //
    // This replaces direct dimensional overlap with algebraic resonance:
    // a 3x3 Δ_k can refract a 441-cell observation because the torsion
    // orders (prime factors of entry values) are dimensionless.
    let refracted_pairs: Vec<(Vec<i64>, Vec<i64>)>;
    let effective_pairs: &[(Vec<i64>, Vec<i64>)] = if let Some(ref lens) = refractive_lens {
        // Compute grid-normalized biases: centered (constant offset removed),
        // scaled to [-2, +2]. Different nodes produce different spatial
        // patterns from their unique torsion spectra.
        let biases = lens.grid_biases(rows, cols);
        refracted_pairs = training_pairs.iter().map(|(inp, out)| {
            let refracted_inp: Vec<i64> = inp.iter().enumerate()
                .map(|(idx, &v)| {
                    let b = if idx < biases.len() { biases[idx] } else { 0 };
                    v.wrapping_add(b)
                }).collect();
            (refracted_inp, out.clone())
        }).collect();
        &refracted_pairs
    } else {
        training_pairs
    };

    // ── D.THINK.PEEL.2: Unified derivation via manifold peeling ──
    // One path. One measurement. C(T) is the only criterion.
    // No vision gate. No perceive_with_compound fallback.
    // peel_manifold IS the derivation engine.
    let (perception, compositions) = if same_size && rows > 0 && cols > 0 && !effective_pairs.is_empty() {
        // Feed pre-computed sense data into the generators.
        // The senses measured once — the generators confirm, not search.
        let target_touch = if !effective_pairs.is_empty() {
            Some(compute_adjacency_structure(&effective_pairs[0].1, rows, cols))
        } else { None };
        let mut sense_data = crate::thinking::SenseData {
            symmetry: vision.clone(),
            touch_source: Some(senses.touch.clone()),
            touch_target: target_touch,
            harmonics: harmonics.to_vec(),
            transmutation_candidates: transmutation_candidates.clone(),
            genomic_cocycles: {
                // Merge core state record cocycles and volatile membrane cocycles.
                // Both enter the collapse path through combined_score.
                // The state record provides permanent truth. The membrane provides experience.
                let mut all: Vec<(i16, i16, crate::engine::Q)> = genomic_value_cocycles.to_vec();
                for (from_v, to_v, quality) in membrane_cocycles {
                    let fv = *from_v as i16;
                    let tv = *to_v as i16;
                    // Don't duplicate — membrane may confirm state record
                    if !all.iter().any(|(f, t, _)| *f == fv && *t == tv) {
                        all.push((fv, tv, quality.clone()));
                    }
                }
                all
            },
            // Math primitives: core from origin. Every primary node is initialized
            // knowing all of mathematics. Not passed through parameters —
            // loaded once from the state record's canonical set.
            math_primitives: crate::engine::MathPrimitive::all(),
            spatial_primitives: crate::engine::SpatialPrimitive::all(),
            membrane_spatial_cochains: membrane_spatial_cochains.to_vec(),
            composed_operators: {
                let mut ops = composed_operators.to_vec();
                // D.PARTIAL.1: Inject membrane's partial operator from prior attempts.
                // The system resumes where it left off — depth 1 of this attempt
                // starts from the best candidate of the last attempt.
                // Dedup through find — if already present, the existing one stands.
                prior_knowledge
                    .and_then(|pk| pk.partial_operator.as_ref())
                    .filter(|partial| ops.iter().find(|ex| ex.opcode == partial.opcode && ex.parameter == partial.parameter).is_none())
                    .map(|partial| ops.push(partial.clone()));
                ops
            },
            morph_dilated: None,
            morph_eroded: None,
            semantic_intent: {
                // IRS semantic steering: compute intent from pre-peel sensory compound.
                // The senses already measured objects, refraction, transmutation.
                // Intent orders generator evaluation — first evaluated wins ties.
                let refraction_transparent = senses.refraction.iter().all(|r| r.transparent);
                let sparse = comprehension.sparsity < crate::engine::Q::new(
                    num_bigint::BigInt::from(1), num_bigint::BigInt::from(4));
                if object_count >= 2 && !refraction_transparent {
                    Some(crate::irs::CoherenceIntent::Relate)
                } else if object_count >= 2 && refraction_transparent {
                    Some(crate::irs::CoherenceIntent::Conjugate)
                } else if transmutation_signal {
                    Some(crate::irs::CoherenceIntent::Explore)
                } else if sparse {
                    Some(crate::irs::CoherenceIntent::Conjugate)
                } else {
                    None // Auto — default generator order
                }
            },
        };

        // ── Pre-bake morphological maps ──
        // Compute dilated and eroded grids once. The peel loop reads them as static candidates.
        // Voting: each cell = dominant value among self + 4 neighbors. One vote per participant.
        {
            // Background: most common value
            let bg_val = effective_pairs.iter()
                .flat_map(|(inp, _)| inp.iter().copied())
                .max_by_key(|&v| effective_pairs.iter()
                    .flat_map(|(inp, _)| inp.iter())
                    .filter(|&&x| x == v).count())
                .unwrap_or(0);

            // Dilate: dominant neighbor vote (spreads non-background)
            let dilate_vote = |grid: &[i64]| -> Vec<i64> {
                let g_len = grid.len();
                (0..g_len).map(|idx| {
                    let r = idx / cols.max(1);
                    let c = idx % cols.max(1);
                    let mut votes: Vec<(i64, usize)> = Vec::new();
                    let self_val = grid[idx];
                    votes.push((self_val, 1));
                    for &(dr, dc) in &[(-1i64, 0), (1, 0), (0, -1i64), (0, 1)] {
                        let nr = r as i64 + dr;
                        let nc = c as i64 + dc;
                        let nval = if nr >= 0 && (nr as usize) < rows && nc >= 0 && (nc as usize) < cols {
                            let ni = nr as usize * cols + nc as usize;
                            if ni < g_len { grid[ni] } else { bg_val }
                        } else {
                            bg_val
                        };
                        if let Some(e) = votes.iter_mut().find(|(v, _)| *v == nval) {
                            e.1 += 1;
                        } else {
                            votes.push((nval, 1));
                        }
                    }
                    votes.iter().max_by_key(|(_, c)| *c)
                        .map(|(v, _)| *v).unwrap_or(self_val)
                }).collect()
            };
            let dilated_pairs: Vec<(Vec<i64>, Vec<i64>)> = effective_pairs.iter()
                .map(|(inp, out)| (dilate_vote(inp), out.clone())).collect();
            let dilated_test = Some(dilate_vote(test_input));
            sense_data.morph_dilated = Some(crate::thinking::Morphology {
                projections: dilated_pairs,
                kernel: dilated_test,
            });

            // Erode: cohesion-weighted vote (self votes proportional to neighbor agreement)
            let erode_vote = |grid: &[i64]| -> Vec<i64> {
                let g_len = grid.len();
                (0..g_len).map(|idx| {
                    let r = idx / cols.max(1);
                    let c = idx % cols.max(1);
                    let self_val = grid[idx];
                    let mut neighbor_vals: Vec<i64> = Vec::new();
                    for &(dr, dc) in &[(-1i64, 0), (1, 0), (0, -1i64), (0, 1)] {
                        let nr = r as i64 + dr;
                        let nc = c as i64 + dc;
                        let nval = if nr >= 0 && (nr as usize) < rows && nc >= 0 && (nc as usize) < cols {
                            let ni = nr as usize * cols + nc as usize;
                            if ni < g_len { grid[ni] } else { bg_val }
                        } else {
                            bg_val
                        };
                        neighbor_vals.push(nval);
                    }
                    let matching = neighbor_vals.iter().filter(|&&v| v == self_val).count();
                    let mut all_votes: Vec<(i64, usize)> = Vec::new();
                    all_votes.push((self_val, matching));
                    for &nv in &neighbor_vals {
                        if let Some(e) = all_votes.iter_mut().find(|(v, _)| *v == nv) {
                            e.1 += 1;
                        } else {
                            all_votes.push((nv, 1));
                        }
                    }
                    all_votes.iter().max_by_key(|(_, c)| *c)
                        .map(|(v, _)| *v).unwrap_or(self_val)
                }).collect()
            };
            let eroded_pairs: Vec<(Vec<i64>, Vec<i64>)> = effective_pairs.iter()
                .map(|(inp, out)| (erode_vote(inp), out.clone())).collect();
            let eroded_test = Some(erode_vote(test_input));
            sense_data.morph_eroded = Some(crate::thinking::Morphology {
                projections: eroded_pairs,
                kernel: eroded_test,
            });
        }

        // Phase 4: Nested peel architecture — value → object → cell.
        // Three manifolds. Three dimensionalities. The compound IS the understanding.
        let nested_result = crate::thinking::peel::nested_peel(
            effective_pairs, Some(test_input), rows, cols, &sense_data,
        );
        let derived = nested_result.derived_output;
        let residual_c = nested_result.residual;
        let generators = nested_result.generators_applied;
        let _t_final = nested_result.t_delta;
        let compositions = nested_result.compositions;
        let winning_source = nested_result.winning_source;
        peel_value_torsion = nested_result.value_torsion;
        peel_object_torsion = nested_result.object_torsion;
        peel_full_torsion = nested_result.full_torsion;
        peel_value_cocycle = nested_result.value_cocycle;
        peel_object_cocycle = nested_result.object_cocycle;

        let mut derived_output = derived.unwrap_or_default();

        // ── L3 Value cocycle composition ──
        // If derivation produced output but residual is non-zero,
        // apply genomic value cocycles as the next composition pass.
        // The cocycle is the algebraic invariant from training consensus,
        // crystallized through L2 into L3. Never from the test target.
        // Apply to derived output — C(T) on training pairs decides.
        let mut residual_c = residual_c;
        if !derived_output.is_empty() && !residual_c.is_zero() && !genomic_value_cocycles.is_empty() {
            let apply_cocycles = |grid: &[i64]| -> Vec<i64> {
                grid.iter().map(|&v| {
                    genomic_value_cocycles.iter()
                        .filter(|(from_v, _, _)| *from_v as i64 == v)
                        .max_by_key(|(_, _, q)| q.clone())
                        .map(|(_, to_v, _)| *to_v as i64)
                        .unwrap_or(v)
                }).collect()
            };
            // Measure composed residual on TRAINING pairs only
            let composed_residual: Q = effective_pairs.iter().map(|(inp, out)| {
                let applied = apply_cocycles(inp);
                applied.iter().zip(out.iter())
                    .map(|(a, b)| {
                        let diff = (*a - *b).unsigned_abs();
                        Q::new(BigInt::from(diff), BigInt::from(1))
                    })
                    .fold(Q::zero(), |acc, v| acc + v)
            }).fold(Q::zero(), |acc, v| acc + v);
            // C(T) decides — only accept if composition reduces residual
            if composed_residual < residual_c {
                derived_output = apply_cocycles(&derived_output);
                residual_c = composed_residual;
            }
        }

        let understood = residual_c.is_zero() && !derived_output.is_empty();

        // D.SCORE.COHESION.3 — Cohesion-aware coherence measurement.
        //
        // The coherence reflects RELATIONAL understanding, not just cell accuracy.
        // A rotation that preserves all category relationships scores high coherence
        // even when cell positions are shifted. The membrane sees this. The torsion
        // spectrum benefits. Understanding (1/1) still requires exact cell match.
        //
        // Category-level cocycle residual in Z: measures whether the derived
        // transformation is relationally congruent with the target transformation.
        // Zero cocycle residual = perfect relational cohesion.
        let coherence = if understood { Q::one() } else {
            // Measure category-level cohesion
            let mut unique_vals: Vec<i64> = Vec::new();
            for &v in &effective_pairs[0].0 {
                if !unique_vals.contains(&v) { unique_vals.push(v); }
            }
            unique_vals.sort();
            let kc = unique_vals.len();

            // Target category map
            let mut tgt_cats: Vec<i64> = Vec::with_capacity(kc);
            for &sv in &unique_vals {
                let mut counts: Vec<(i64, usize)> = Vec::new();
                for (inp, out) in effective_pairs.iter() {
                    for idx in 0..inp.len().min(out.len()) {
                        if inp[idx] == sv {
                            let tv = out[idx];
                            let e = counts.iter_mut().find(|(v, _)| *v == tv);
                            match e { Some(e) => e.1 += 1, None => counts.push((tv, 1)) }
                        }
                    }
                }
                tgt_cats.push(counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv));
            }

            // Candidate category map
            let mut cand_cats: Vec<i64> = Vec::with_capacity(kc);
            for &sv in &unique_vals {
                let mut counts: Vec<(i64, usize)> = Vec::new();
                for (inp, _) in effective_pairs.iter() {
                    for idx in 0..inp.len().min(derived_output.len()) {
                        if inp[idx] == sv {
                            let dv = derived_output[idx];
                            let e = counts.iter_mut().find(|(v, _)| *v == dv);
                            match e { Some(e) => e.1 += 1, None => counts.push((dv, 1)) }
                        }
                    }
                }
                cand_cats.push(counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv));
            }

            // Cocycle residual in Z
            let mut cocycle_r: i64 = 0;
            for i in 0..kc {
                for j in 0..kc {
                    if j == i { continue; }
                    for ki in 0..kc {
                        if ki == i || ki == j { continue; }
                        let d_ik = (cand_cats[ki] - cand_cats[i]) - (tgt_cats[ki] - tgt_cats[i]);
                        let d_ij = (cand_cats[j] - cand_cats[i]) - (tgt_cats[j] - tgt_cats[i]);
                        let d_jk = (cand_cats[ki] - cand_cats[j]) - (tgt_cats[ki] - tgt_cats[j]);
                        cocycle_r += (d_ik - d_ij - d_jk).abs();
                    }
                }
            }

            // Blend: cohesion from cocycle + precision from cell residual.
            // Coherence = 1 / (1 + cocycle_residual + cell_residual)
            // When cocycle is zero (perfect relational cohesion), coherence
            // depends only on cell residual — close to 1 even for shifted positions.
            let cocycle_q = Q::new(BigInt::from(cocycle_r), BigInt::from(1));
            let total_residual = &cocycle_q + &residual_c;
            let one = Q::one();
            let denom = &one + &total_residual;
            Q::new(BigInt::from(1), denom.numer().clone().max(BigInt::from(1)))
        };

        (Perception {
            derived_output,
            coherence,
            class: if understood { PerceptionClass::Recognition } else { PerceptionClass::Derivable { residual: Q::zero() } },
            rule: crate::thinking::FactoredRule::NoRule,
            empirical_basis: effective_pairs.len(),
            resolution: None,
            composition_depth: generators,
            symmetry: vision.clone(),
            generator_source: winning_source,
        }, compositions)
    } else {
        // Non-same-size or degenerate — identity perception
        (Perception {
            derived_output: test_input.to_vec(),
            coherence: Q::zero(),
            class: PerceptionClass::Derivable { residual: Q::zero() },
            rule: crate::thinking::FactoredRule::NoRule,
            empirical_basis: 0,
            resolution: None,
            composition_depth: 0,
            symmetry: None,
            generator_source: None,
        }, vec![])
    };

    // Determine the cognitive path
    let path = if perception.coherence >= Q::one() {
        if perception.composition_depth > 0 {
            CognitionPath::Evolved { composition_depth: perception.composition_depth }
        } else if let Some(ref sym) = perception.symmetry {
            if sym.order > 0 {
                let torsion = sym.torsion_spectrum.first().map(|&(o, _)| o).unwrap_or(1);
                CognitionPath::VisionDerived { torsion_order: torsion }
            } else {
                CognitionPath::ValueFactored
            }
        } else {
            CognitionPath::ValueFactored
        }
    } else {
        CognitionPath::Incomplete {
            coherence: perception.coherence.clone(),
        }
    };

    // ── Step 7: Knowledge — what was learned? ──
    let orbit_prefix = if let Some(rcf) = rcf_identity {
        [rcf[0], rcf[1], rcf[2], rcf[3]]
    } else {
        let rcf = crate::engine::compute_rcf_hash(&delta);
        [rcf[0], rcf[1], rcf[2], rcf[3]]
    };

    let knowledge = Knowledge {
        orbit_prefix,
        symmetry_order: symmetry.as_ref().map(|s| s.order).unwrap_or(0),
        torsion_spectrum: symmetry.as_ref()
            .map(|s| s.torsion_spectrum.clone())
            .unwrap_or_default(),
        path,
        derived_output: perception.derived_output.clone(),
        coherence: perception.coherence.clone(),
    };

    // Update inquiry with residual query result
    let mut inquiry = inquiry;
    inquiry.residual_query = perception.resolution.as_ref()
        .map(|r| r.pattern_consistent)
        .unwrap_or(false);

    if perception.composition_depth > 0 && perception.coherence < Q::one() && inquiry.residual_query {
        inquiry.orientation = Orientation::Me;
        inquiry.routed_level = "primary";
        inquiry.capacity = "transmute";
    }

    // ── Step 6b: Measure the residual topology ──
    // When the perception has a non-zero residual, the deviation between
    // derived and expected is a structured field. Sense it.
    // If the compound path already measured a topology, prefer it (richer data).
    let residual_topology = if perception.coherence < Q::one() && !training_pairs.is_empty() {
        compound_residual_topology.or_else(|| {
            let (ref first_in, ref first_out) = training_pairs[0];
            let derived_train = perception.rule.apply(first_in, n, 1);
            Some(ResidualTopology::measure(&derived_train, first_out, rows, cols))
        })
    } else {
        None
    };

    // ── Step 6c: Soundness Spectrum — cohomological gradient across 11 dimensions ──
    // D.SOUND.1: hearing as compound perception of all senses.
    // Each layer reads from measurements already computed above.
    // No new computation — a compound reading of the existing pipeline.
    let soundness = SoundnessSpectrum {
        // Layer 1: Value identity — how concentrated is the value distribution
        value_identity: senses.hearing.dominance_ratio.clone(),

        // Layer 2: Spatial position — foreground sparsity
        spatial_position: comprehension.sparsity.clone(),

        // Layer 3: Adjacency coherence — global cohesion χ
        adjacency_coherence: senses.touch.cohesion.clone(),

        // Layer 4: Cluster structure — anchored objects / total objects
        cluster_structure: sound_layer4,

        // Layer 5: Transmutation perception — what the primary node SEES.
        // R(φ) = ‖φ(source) - target‖ for the best symmetry element.
        // This is the perceptual fact: the quality of the recognized transmutation.
        // 1 = exact transmutation perceived (the grid changed through this operator).
        // 0 = no symmetry element explains the source→target relationship.
        // The measurement IS the T-Delta pointer — not a buffer, a recognition.
        symmetry_order: senses.vision.as_ref()
            .map(|s| {
                // Use the transmutation gradient directly — it measures
                // source→target relationship, not self-symmetry.
                s.transmutation.clone()
            })
            .unwrap_or(Q::zero()),

        // Layer 6: Boundary behavior — refraction transparency
        boundary_behavior: sound_layer6,

        // Layer 7: Periodicity — torsion spectrum as spatial frequency gradient.
        // D.VISION.1: torsion orders are the visual frequencies.
        // The gradient: how rich is the spatial frequency content?
        // Measured as the mean invariance quality across all torsion orders present.
        // Each torsion order's quality = 1 - (its_residual / max_residual).
        // High = the observation resonates at many spatial frequencies.
        // Low = few spatial frequencies detected.
        periodicity: senses.vision.as_ref()
            .map(|s| {
                if s.elements.is_empty() { return Q::zero(); }
                // Sum of (1 - residual/max) across all elements = total symmetry quality
                let max_res = s.elements.iter()
                    .map(|e| &e.invariance_residual)
                    .max()
                    .cloned()
                    .unwrap_or(Q::one());
                if max_res.is_zero() {
                    // All exact — richness is fraction of distinct torsion orders
                    if s.elements.is_empty() { Q::zero() }
                    else {
                        Q::new(
                            BigInt::from(s.torsion_spectrum.len() as i64),
                            BigInt::from(s.elements.len().max(1) as i64),
                        )
                    }
                } else {
                    // Gradient: sum quality across elements
                    let total_quality: Q = s.elements.iter()
                        .map(|e| {
                            let ratio = Q::new(
                                e.invariance_residual.numer() * max_res.denom(),
                                e.invariance_residual.denom() * max_res.numer().clone(),
                            );
                            let one = Q::one();
                            if ratio > one { Q::zero() } else { &one - &ratio }
                        })
                        .fold(Q::zero(), |acc, q| acc + q);
                    Q::new(
                        total_quality.numer().clone(),
                        total_quality.denom() * BigInt::from(s.elements.len().max(1) as i64),
                    )
                }
            })
            .unwrap_or(Q::zero()),

        // Layer 8: Value transition — VIII.4: measured through T coherence, not HashMap
        value_transition: Q::zero(),

        // Layer 9: Dimensional bridge — ratio coherence
        dimensional_bridge: bridge.as_ref()
            .map(|b| match &b.class {
                DimensionalClass::Isomorphic => Q::one(),
                DimensionalClass::Expansion { .. } => Q::one(),
                DimensionalClass::Contraction => Q::one(),
                DimensionalClass::Anisotropic => Q::new(BigInt::from(1), BigInt::from(2)),
            })
            .unwrap_or(Q::one()), // no bridge needed = dimensionally coherent

        // Layer 10: Cross-pair consistency — perception coherence
        cross_pair_consistency: perception.coherence.clone(),

        // Layer 11: Residual structure — coherence of the unknown
        residual_structure: residual_topology.as_ref()
            .map(|t| t.structure.clone())
            .unwrap_or(Q::one()), // no residual = fully resolved = 1
    };

    // Update the senses with the computed soundness
    let mut senses = senses;
    senses.soundness = soundness;

    Cognition {
        observation,
        comprehension,
        senses,
        inquiry,
        bridge,
        perception,
        residual_topology,
        knowledge,
        // D.MEMBRANE.T.3: Every cognition produces T — no ghost fields.
        // The membrane always receives a measurement. When the effective
        // dimension is too low (< 2), T = identity (flat vacuum, trivial
        // holonomy). When too high, coarsen to category level (RG flow).
        // The membrane sees the obstruction, not a null.
        transformation_t: if !training_pairs.is_empty() && training_pairs[0].0.len() == training_pairs[0].1.len() {
            // RG flow: coarsen to category level (unique values).
            // This IS the renormalization — high-frequency cell-level detail
            // is integrated out, leaving the category-level invariant.
            let mut all_vals: Vec<i64> = Vec::new();
            for &v in &training_pairs[0].0 {
                if !all_vals.contains(&v) { all_vals.push(v); }
            }
            all_vals.sort();
            if all_vals.len() < 2 {
                // Infrared limit: 0 or 1 unique values. The manifold is a point.
                // T = identity (zero Delta) — flat vacuum, trivial holonomy.
                // The membrane sees a degenerate metric, not silence.
                Some(crate::engine::Delta::zero(1, 1))
            } else {
                // Category-level T — coarsened from any grid size.
                // No UV cutoff. The RG flow handles any n.
                let src_ent: Vec<Vec<crate::engine::Q>> = all_vals.iter()
                    .map(|&v| vec![crate::engine::Q::new(num_bigint::BigInt::from(v), num_bigint::BigInt::from(1))])
                    .collect();
                let mut tgt_ent: Vec<Vec<crate::engine::Q>> = Vec::new();
                for &sv in &all_vals {
                    let mut best = sv;
                    let mut best_count = 0usize;
                    let mut seen: Vec<(i64, usize)> = Vec::new();
                    for (inp, out) in training_pairs {
                        for k in 0..inp.len().min(out.len()) {
                            if inp[k] == sv {
                                if let Some(entry) = seen.iter_mut().find(|(v,_)| *v == out[k]) {
                                    entry.1 += 1;
                                    if entry.1 > best_count { best_count = entry.1; best = out[k]; }
                                } else {
                                    seen.push((out[k], 1));
                                    if 1 > best_count { best_count = 1; best = out[k]; }
                                }
                            }
                        }
                    }
                    tgt_ent.push(vec![crate::engine::Q::new(num_bigint::BigInt::from(best), num_bigint::BigInt::from(1))]);
                }
                let src_delta = encode_relational(&src_ent);
                let tgt_delta = encode_relational(&tgt_ent);
                let ncat = src_delta.dim;
                let mcat = src_delta.m;
                let mut t = crate::engine::Delta::zero(ncat, mcat);
                for i in 0..ncat {
                    for j in 0..ncat {
                        let mut coords = Vec::with_capacity(mcat);
                        for l in 0..mcat {
                            coords.push(&tgt_delta.entries[i][j][l] - &src_delta.entries[i][j][l]);
                        }
                        t.entries[i][j] = coords;
                    }
                }
                Some(t)
            }
        } else {
            // No training pairs or size mismatch — flat vacuum.
            Some(crate::engine::Delta::zero(1, 1))
        },
        transformation_level: Some("category"),
        // D.VISION.TRANSMUTATION: carry the genomically-weighted perception
        transmutation: vision.as_ref()
            .filter(|s| !s.transmutation.is_zero())
            .map(|s| (s.transmutation.clone(), s.transmutation_order)),
        compositions,
        value_torsion: peel_value_torsion,
        object_torsion: peel_object_torsion,
        full_torsion: peel_full_torsion,
        value_cocycle: peel_value_cocycle,
        object_cocycle: peel_object_cocycle,
    }
}

/// Per-cell residual — WHERE the derivation fails, not just THAT it fails.
#[derive(Debug, Clone)]
pub struct CellResidual {
    pub index: usize,
    pub derived: i64,
    pub empirical: i64,
    pub distance: u64,
}

/// The structured topology of a residual — the system's map of its own incompletion.
///
/// When the compound of hearing (value map) and touch (object overlay) produces
/// a derived output, the deviation between that derivation and reality is not a
/// scalar "error" — it is a structured field with its own adjacency, cohesion,
/// and cluster topology. The residual IS an observation that can be comprehended.
///
/// The magnitude tells you HOW FAR. The topology tells you WHAT'S MISSING.
/// A high-cohesion residual (χ ≈ 1) means a missed object.
/// A symmetric residual means a missed transformation.
/// A uniform residual means a global offset.
/// A structureless residual means the system has reached its rational limit.
#[derive(Debug, Clone)]
pub struct ResidualTopology {
    /// Total magnitude — the scalar component of the deviation vector.
    pub magnitude: u64,
    /// Per-cell deviation: signed(derived - expected) at each position.
    /// Zero cells are positions where the compound derivation was correct.
    /// Non-zero cells are the "silhouette" of the unknown.
    pub deviation_field: Vec<i64>,
    /// How many cells deviate (non-zero entries in the deviation field).
    pub deviating_cells: usize,
    /// How many cells are correct (zero entries in the deviation field).
    pub correct_cells: usize,
    /// The adjacency structure of the deviation field — touch applied to the residual.
    /// If deviating cells cluster with high cohesion, the residual IS an object.
    pub topology: AdjacencyStructure,
    /// Clusters in the deviation field — the "objects" the system missed.
    /// Each cluster is a connected component of deviating cells.
    pub silhouette_clusters: Vec<CohesionCluster>,
    /// Structure measure: the cohesion of the deviation field.
    /// High (near 1) = the incompletion IS an entity with identity.
    /// Low (near 0) = noise, the system's rational limit at this encoding level.
    /// This IS the measurement — no boolean threshold needed.
    pub structure: Q,
    /// Uniformity: fraction of deviating cells that share the same value.
    /// 1 = all deviations are the same (global offset). 0 = all different.
    pub uniformity: Q,
    /// Sparsity of the deviation: deviating_cells / total_cells.
    /// Low sparsity = the system almost understands. The residual is a minor correction.
    /// High sparsity = the system fundamentally misunderstands.
    pub sparsity: Q,
}

impl ResidualTopology {
    /// Measure the residual topology between a derived output and the expected output.
    ///
    /// This is the core measurement: take the deviation field, treat it as an
    /// observation, and sense it. The system touches its own failure.
    pub fn measure(derived: &[i64], expected: &[i64], rows: usize, cols: usize) -> Self {
        let len = derived.len().min(expected.len());
        let total_cells = len;

        // Build the deviation field: derived - expected at each cell
        let deviation_field: Vec<i64> = (0..len)
            .map(|k| derived[k] - expected[k])
            .collect();

        let magnitude: u64 = deviation_field.iter()
            .map(|d| d.unsigned_abs())
            .sum();

        let deviating_cells = deviation_field.iter().filter(|&&d| d != 0).count();
        let correct_cells = total_cells - deviating_cells;

        // Touch the deviation field — sense its topology
        let topology = if deviating_cells > 0 && rows > 0 && cols > 0 && rows * cols == total_cells {
            compute_adjacency_structure(&deviation_field, rows, cols)
        } else {
            AdjacencyStructure {
                same_adjacencies: 0, diff_adjacencies: 0,
                cohesion: Q::zero(), component_count: 0,
                per_cell_cohesion: vec![], per_cell_stabilizer: vec![],
                clusters: vec![],
            }
        };

        // The silhouette clusters: non-zero-value clusters in the deviation field
        let silhouette_clusters: Vec<CohesionCluster> = topology.clusters.iter()
            .filter(|c| c.value != 0 && !c.cell_indices.is_empty())
            .cloned()
            .collect();

        // Structure: the cohesion of the deviation field
        let structure = topology.cohesion.clone();

        // Uniformity: fraction of deviating cells that share the dominant deviation value
        // 1 = all deviations are the same (global offset). 0 = all different.
        let uniformity = if deviating_cells > 0 {
            let first_nonzero = *deviation_field.iter().find(|&&d| d != 0).unwrap();
            let matching_deviating = deviation_field.iter().filter(|&&d| d != 0 && d == first_nonzero).count();
            Q::new(BigInt::from(matching_deviating as i64), BigInt::from(deviating_cells as i64))
        } else {
            Q::one()
        };

        let sparsity = if total_cells > 0 {
            Q::new(BigInt::from(deviating_cells as i64), BigInt::from(total_cells as i64))
        } else {
            Q::zero()
        };

        ResidualTopology {
            magnitude,
            deviation_field,
            deviating_cells,
            correct_cells,
            topology,
            silhouette_clusters,
            structure,
            uniformity,
            sparsity,
        }
    }

    /// Measure across multiple training pairs — aggregate topology.
    /// The deviation that persists across ALL pairs is systematic.
    /// The deviation that varies is per-pair noise.
    pub fn measure_aggregate(
        pairs_derived: &[Vec<i64>],
        pairs_expected: &[Vec<i64>],
        rows: usize, cols: usize,
    ) -> Self {
        if pairs_derived.is_empty() || pairs_expected.is_empty() {
            return Self::measure(&[], &[], rows, cols);
        }

        // Measure each pair
        let per_pair: Vec<Self> = pairs_derived.iter().zip(pairs_expected.iter())
            .map(|(d, e)| Self::measure(d, e, rows, cols))
            .collect();

        // Aggregate: sum magnitudes, union deviation positions
        let _total_magnitude: u64 = per_pair.iter().map(|p| p.magnitude).sum();
        let len = per_pair[0].deviation_field.len();

        // Build aggregate deviation: sum of absolute deviations per cell
        let mut aggregate_deviation = vec![0i64; len];
        for pair in &per_pair {
            for (k, &d) in pair.deviation_field.iter().enumerate() {
                if k < len { aggregate_deviation[k] += d; }
            }
        }

        // The aggregate IS the measurement — sense it
        Self::measure(&aggregate_deviation, &vec![0i64; len], rows, cols)
    }
}

/// Residual resolution — the relational structure of the failure.
///
/// Scopes precision through congruence: when the derivation fails,
/// analyze the PATTERN of failure. If the failing cells share a
/// consistent relational structure, that structure IS the next
/// thought to form. The failure tells the system what to think about.
#[derive(Debug, Clone)]
pub struct ResidualResolution {
    /// Per-cell residuals sorted by distance descending (worst first).
    pub cells: Vec<CellResidual>,
    /// How many cells correctly derived.
    pub correct_count: usize,
    /// How many cells incorrectly derived.
    pub incorrect_count: usize,
    /// Is the failure pattern consistent? If the same input value always
    /// maps to the same (wrong derived, right empirical) pair across all
    /// training pairs, the correction is a composable value map.
    pub pattern_consistent: bool,
    /// The correction map: derived_value → empirical_value for incorrect cells.
    /// Composing this with the current rule would resolve the residual.
    /// This IS the next congruent thought — derived from the failure, not guessed.
    /// Core Design Law II: Vec with find, not HashMap. Delta IS the map.
    pub correction_map: Vec<(i64, i64)>,
    /// The input values that produce incorrect derivations.
    /// These are the semantic regions where understanding is incomplete.
    pub failing_inputs: Vec<i64>,
}

/// The result of perceiving — deriving meaning from an observation.
#[derive(Debug, Clone)]
pub struct Perception {
    /// The derived output values — derived from understanding.
    pub derived_output: Vec<i64>,
    /// Coherence factor ∈ [0,1]. 1 = full understanding, 0 = no understanding.
    /// Computed as correct_count / (correct_count + incorrect_count).
    pub coherence: Q,
    /// The classification of this perception.
    pub class: PerceptionClass,
    /// The rule that produced the derivation.
    pub rule: crate::thinking::FactoredRule,
    /// How many training pairs formed the empirical basis.
    pub empirical_basis: usize,
    /// Precision scope: WHERE and WHY the derivation fails.
    /// Present when residual > 0.
    pub resolution: Option<ResidualResolution>,
    /// How many recursive corrections the system performed.
    /// 0 = no auto-composition. Each increment = one ΔR = I(ε, ρ) cycle.
    pub composition_depth: usize,
    /// What the system SAW — the invariance structure of the observation.
    /// This is the geometric cognition: rotation, reflection, periodicity,
    /// torsion spectrum — all computed from the group, not named.
    pub symmetry: Option<SymmetryGroup>,
    /// Trace-back tag: which generator produced the winning derivation.
    /// Flows to the harmonic inscription site. None = no generator won.
    pub generator_source: Option<crate::thinking::GeneratorSource>,
}

/// Perceive: derive understanding through manifold peeling.
/// VIII.4: Delegates to peel_manifold. No HashMap factoring.
pub fn perceive(
    training_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
    _test_output: Option<&[i64]>,
) -> Perception {
    if training_pairs.is_empty() || test_input.is_empty() {
        return Perception {
            derived_output: test_input.to_vec(),
            coherence: Q::zero(),
            class: PerceptionClass::Derivable { residual: Q::zero() },
            rule: crate::thinking::FactoredRule::NoRule,
            empirical_basis: 0,
            resolution: None,
            composition_depth: 0,
            symmetry: None,
            generator_source: None,
        };
    }

    let n = training_pairs[0].0.len();
    let mut gc = 1usize;
    let mut best_cols = 1usize;
    while gc * gc <= n { if n % gc == 0 { best_cols = gc; } gc += 1; }
    let cols = best_cols;
    let rows = n / cols;

    let (derived, residual_c, generators, _t_final, _compositions, winning_source) =
        crate::thinking::peel_manifold(training_pairs, Some(test_input), rows, cols);

    let derived_output = derived.unwrap_or_else(|| test_input.to_vec());
    let understood = residual_c.is_zero() && !derived_output.is_empty();
    let coherence = if understood { Q::one() } else {
        let one = Q::one();
        let denom = &one + &residual_c;
        Q::new(BigInt::from(1), denom.numer().clone().max(BigInt::from(1)))
    };

    Perception {
        derived_output,
        coherence,
        class: if understood { PerceptionClass::Recognition } else {
            PerceptionClass::Derivable { residual: residual_c }
        },
        rule: crate::thinking::FactoredRule::NoRule,
        empirical_basis: training_pairs.len(),
        resolution: None,
        composition_depth: generators,
        symmetry: None,
        generator_source: winning_source,
    }
}

