// A.5 — OPERATOR SEARCH: Find A that maps Δ_source to Δ_target
// ═══════════════════════════════════════════════════════════════════════

/// Distance functional: D(A) = ‖Π_G(A·Δ_s·A⁻¹) - Δ_t‖ (L1)
/// Measures how well operator A maps source state to target state.
/// D = 0 iff A perfectly transforms source to target.
pub fn operator_distance(op: &Operator, source: &Delta, target: &Delta) -> Q {
    match op.apply(source) {
        Ok(conjugated) => {
            let projected = crate::engine::pi_g_project(&conjugated);
            let mut dist = Q::zero();
            for i in 0..source.dim {
                for j in 0..source.dim {
                    for l in 0..source.m {
                        let diff = &projected.entries[i][j][l] - &target.entries[i][j][l];
                        if diff < Q::zero() { dist -= &diff; } else { dist += &diff; }
                    }
                }
            }
            dist
        }
        Err(_) => Q::new(BigInt::from(i64::MAX), BigInt::from(1)), // sentinel
    }
}

/// A.5 — Operator search via perturbation analysis.
///
/// Find A ∈ GL_n^+(Q) that minimizes D(A) = ‖A·Δ_s·A⁻¹ - Δ_t‖ (L1).
///
/// Uses the perturbation formula from engine.rs to build the linear system.
/// The gradient uses sign(residual) × perturbation (L1 subgradient)
/// instead of residual × perturbation (L2 gradient).
///
/// At A = I (identity): AΔA⁻¹ = Δ_s, so the residual is (Δ_s - Δ_t).
/// The perturbation ∂Δ_{ij,l}/∂ε_{rs} is the SAME formula from engine.rs.
///
/// L1 subgradient: ∂|r|/∂ε = sign(r) · ∂r/∂ε.
/// The normal equations approximate the Hessian as AᵀA (same structure,
/// the sign weighting enters through the right-hand side).
pub fn search_operator(source: &Delta, target: &Delta) -> Option<(Operator, Q, Q)> {
    let n = source.dim;
    let m = source.m;
    assert_eq!(n, target.dim, "source and target must have same dimension");
    assert_eq!(m, target.m, "source and target must have same coordinate count");

    let dirs = matrix::independent_dims(n);
    let d = dirs.len();

    // Compute residual: Δ_s - Δ_t (what needs to change)
    // L1 gradient: sign(residual) × perturbation
    let mut ata = vec![vec![Q::zero(); d]; d];
    let mut atr = vec![Q::zero(); d];
    let mut dist_before = Q::zero();

    for i in 0..n {
        for j in 0..n {
            for l in 0..m {
                let residual = &source.entries[i][j][l] - &target.entries[i][j][l];
                if residual.is_zero() { continue; }
                // L1 distance
                if residual < Q::zero() { dist_before -= &residual; } else { dist_before += &residual; }

                // Sign of residual for L1 subgradient
                let sign_r = if residual < Q::zero() {
                    Q::new(BigInt::from(-1), BigInt::from(1))
                } else {
                    Q::new(BigInt::from(1), BigInt::from(1))
                };

                // Perturbation of Δ_s at (i,j,l) by each direction
                let mut pert_row: Vec<(usize, Q)> = Vec::new();
                for (idx, &(r, s)) in dirs.iter().enumerate() {
                    let p = crate::engine::perturbation(source, i, j, l, r, s);
                    if !p.is_zero() {
                        pert_row.push((idx, p));
                    }
                }

                // L1 subgradient: Aᵀ·sign(r) instead of Aᵀ·r
                for &(ci, ref pi) in &pert_row {
                    atr[ci] = &atr[ci] + &(pi * &sign_r);
                    for &(cj, ref pj) in &pert_row {
                        ata[ci][cj] = &ata[ci][cj] + &(pi * pj);
                    }
                }
            }
        }
    }

    if dist_before.is_zero() {
        // Source already equals target — identity is the operator
        return Some((
            Operator {
                id: 0,
                matrix: matrix::identity(n),
                matrix_inv: matrix::identity(n),
                det_sign_positive: true,
            },
            Q::zero(), Q::zero(),
        ));
    }

    // Solve normal equations: AᵀA·ε = -Aᵀr
    let mut epsilon = match matrix::invert(&ata) {
        Some(ata_inv) => {
            let mut eps = vec![Q::zero(); d];
            for i in 0..d {
                for j in 0..d {
                    eps[i] = &eps[i] - &(&ata_inv[i][j] * &atr[j]);
                }
            }
            eps
        }
        None => return None,
    };

    // Cap step size
    let max_abs = epsilon.iter()
        .map(|e| if e < &Q::zero() { -e.clone() } else { e.clone() })
        .max()
        .unwrap_or(Q::one());
    let cap = Q::new(BigInt::from(1), BigInt::from(5));
    if max_abs > cap {
        let scale = &cap / &max_abs;
        epsilon = epsilon.iter().map(|e| e * &scale).collect();
    }

    // Build operator and measure distance after
    let op = matrix::operator_from_epsilons(&epsilon, &dirs, n, 0)?;
    let dist_after = operator_distance(&op, source, target);

    Some((op, dist_before, dist_after))
}

/// D.ARC.GROUP.PRODUCT.1 — Value-action operator search.
///
/// Conjugation AΔA⁻¹ acts on node indices (G_SPATIAL).
/// Value action acts on node content (G_VALUE).
///
/// For the value action: perturbing cell k's value by ε changes
/// Δ_{ij,0} by (δ_{jk} - δ_{ik})·ε for the value coordinate.
/// Position coordinates (l=1,2) are unchanged.
///
/// This solves for the vector v ∈ Q^n such that
/// Δ'_{ij,0} = (v_j + val_j) - (v_i + val_i) matches target_{ij,0}.
/// Equivalently: v_j - v_i = target_{ij,0} - source_{ij,0} for all (i,j).
/// This is a linear system with solution v_k = target_value_k - source_value_k
/// (up to a constant offset, anchored at v_0 = 0).
pub fn search_value_operator(
    source: &Delta, target: &Delta, source_values: &[i64], target_values: &[i64],
) -> Option<(Vec<Q>, Q, Q)> {
    let n = source.dim;
    if n != source_values.len() || n != target_values.len() { return None; }

    // The value action: compute the per-cell value change needed
    // v_k = target_k - source_k
    let value_changes: Vec<Q> = (0..n)
        .map(|k| Q::new(
            BigInt::from(target_values[k] - source_values[k]),
            BigInt::from(1),
        ))
        .collect();

    // Compute distance before (identity value action)
    let mut dist_before = Q::zero();
    for i in 0..n {
        for j in (i+1)..n {
            // Value coordinate only (l=0) — position coords don't change
            let source_val_diff = &source.entries[i][j][0];
            let target_val_diff = &target.entries[i][j][0];
            let residual = source_val_diff - target_val_diff;
            if !residual.is_zero() {
                if residual < Q::zero() { dist_before -= &residual; } else { dist_before += &residual; }
            }
        }
    }

    // Compute distance after applying value changes
    // New Δ_{ij,0} = (source_j + v_j) - (source_i + v_i) = source_{ij,0} + (v_j - v_i)
    let mut dist_after = Q::zero();
    for i in 0..n {
        for j in (i+1)..n {
            let new_val_diff = &source.entries[i][j][0] + &value_changes[j] - &value_changes[i];
            let target_val_diff = &target.entries[i][j][0];
            let residual = &new_val_diff - target_val_diff;
            if !residual.is_zero() {
                if residual < Q::zero() { dist_after -= &residual; } else { dist_after += &residual; }
            }
        }
    }

    Some((value_changes, dist_before, dist_after))
}

/// D.PERC.TOPOLOGY.1 — Morphism finder between Delta spaces of different dimension.
///
/// When source has n_s objects and target has n_t objects (n_s ≠ n_t),
/// the transformation changes the object count. This function finds the
/// morphism Pi: {0..n_t-1} → {0..n_s-1} such that the relational structure
/// is preserved: Delta_target[i][j] ≈ Delta_source[Pi(i)][Pi(j)] across all
/// training pairs.
///
/// The morphism is measured algebraically: for each target object i, find which
/// source object has the same relational signature (its row in the Delta matrix)
/// consistently across all training pairs.
///
/// Returns: the morphism as a mapping from target indices to source indices,
/// and the projected pairs (both at n_t dimension) for the engine to process.
pub fn factor_topology(
    source_deltas: &[Delta],
    target_deltas: &[Delta],
) -> Option<TopologyMorphism> {
    if source_deltas.is_empty() || target_deltas.is_empty() { return None; }
    if source_deltas.len() != target_deltas.len() { return None; }

    let n_s = source_deltas[0].dim;
    let n_t = target_deltas[0].dim;
    let m = source_deltas[0].m;

    // Verify all pairs have consistent dimensions
    if !source_deltas.iter().all(|d| d.dim == n_s && d.m == m) { return None; }
    if !target_deltas.iter().all(|d| d.dim == n_t && d.m == m) { return None; }

    if n_s == n_t {
        // Same dimension — identity morphism
        return Some(TopologyMorphism {
            n_source: n_s,
            n_target: n_t,
            m,
            mapping: (0..n_t).collect(),
            mapped_count: n_t,
        });
    }

    // For each target object i, find source objects with matching relational signature.
    // Signature of object i in Delta = the vector of all Δ_{ij,l} for all j, l.
    // Two objects match if their signatures are equal across ALL training pairs.
    let mut mapping: Vec<Option<usize>> = vec![None; n_t];

    for ti in 0..n_t {
        // Collect candidate source objects from first pair
        let mut candidates: Vec<usize> = (0..n_s).collect();

        // Filter by relational consistency across all pairs
        for pair_idx in 0..source_deltas.len() {
            let _sd = &source_deltas[pair_idx];
            let _td = &target_deltas[pair_idx];

            candidates.retain(|&_si| {
                // Check: does source object si have the same relational signature
                // as target object ti in this pair?
                // Compare Δ_source[si][sj] with Δ_target[ti][tj] for all mapped pairs
                // For initial filtering: compare the diagonal entry (self-relation = 0)
                // and the magnitude of the relational vector
                true // initial pass — refine below
            });
        }

        // Refine: for each candidate, check if the VALUE at this object
        // matches across all pairs. The relational signature at m=0 (value coord)
        // tells us the value difference with all other objects.
        // The candidate that matches on the value coordinate across all pairs
        // is the morphism target.
        candidates.retain(|&si| {
            // For each pair: the sum of absolute value differences from this object
            // to all other mapped objects should match between source and target.
            // This is the relational fingerprint.
            for pair_idx in 0..source_deltas.len() {
                let sd = &source_deltas[pair_idx];
                let td = &target_deltas[pair_idx];

                // Compare value coordinate signature: Σ|Δ_{i,j,0}| for all j
                let mut source_sig = Q::zero();
                for sj in 0..n_s {
                    if sj != si { source_sig += { let v = &sd.entries[si][sj][0]; if v < &Q::zero() { -v.clone() } else { v.clone() } }; }
                }
                let mut target_sig = Q::zero();
                for tj in 0..n_t {
                    if tj != ti { target_sig += { let v = &td.entries[ti][tj][0]; if v < &Q::zero() { -v.clone() } else { v.clone() } }; }
                }
                if source_sig != target_sig { return false; }
            }
            true
        });

        if candidates.len() == 1 {
            mapping[ti] = Some(candidates[0]);
        }
    }

    let mapped_count = mapping.iter().filter(|m| m.is_some()).count();
    let full_mapping: Vec<usize> = mapping.iter().map(|m| m.unwrap_or(0)).collect();

    if mapped_count == 0 { return None; }

    Some(TopologyMorphism {
        n_source: n_s,
        n_target: n_t,
        m,
        mapping: full_mapping,
        mapped_count,
    })
}

/// The measured morphism between two Delta spaces of different dimension.
#[derive(Debug, Clone)]
pub struct TopologyMorphism {
    /// Source object count.
    pub n_source: usize,
    /// Target object count.
    pub n_target: usize,
    /// Coordinate dimension.
    pub m: usize,
    /// Mapping: target_object[i] corresponds to source_object[mapping[i]].
    pub mapping: Vec<usize>,
    /// How many target objects were successfully mapped.
    pub mapped_count: usize,
}

/// Reduce a rational to bounded precision by truncating to N decimal digits.
/// This prevents BigRational denominators from growing unboundedly during
/// iterated operator search while keeping the arithmetic exact at each step.
fn reduce_precision(q: &Q, max_denom: i64) -> Q {
    let n = q.numer();
    let d = q.denom();
    let d_i64: i64 = d.try_into().unwrap_or(max_denom);
    if d_i64.abs() <= max_denom { return q.clone(); }
    // Scale down: multiply numer and denom by max_denom/denom
    let scale = Q::new(BigInt::from(max_denom), d.clone());
    let new_n = (n * scale.numer()) / scale.denom();
    Q::new(new_n, BigInt::from(max_denom))
}

/// Reduce all entries of a Delta to bounded precision.
fn reduce_delta_precision(delta: &mut Delta, max_denom: i64) {
    for i in 0..delta.dim {
        for j in 0..delta.dim {
            for l in 0..delta.m {
                delta.entries[i][j][l] = reduce_precision(&delta.entries[i][j][l], max_denom);
            }
        }
    }
}

/// Iterated operator search — apply search_operator repeatedly,
/// composing the operators at each step. Converges quadratically.
/// Uses bounded precision to prevent BigRational blowup on multi-channel.
pub fn search_operator_iterated(
    source: &Delta,
    target: &Delta,
    max_iters: usize,
) -> Option<(Operator, Q, Q)> {
    let n = source.dim;
    let mut current = source.clone();
    let mut composed_mat = matrix::identity(n);
    let mut composed_inv = matrix::identity(n);
    let mut dist_initial = Q::zero();
    let mut first = true;

    for _iter in 0..max_iters {
        let (op, d_before, _d_after) = search_operator(&current, target)?;

        if first {
            dist_initial = d_before.clone();
            first = false;
        }

        if d_before.is_zero() { break; } // converged

        // Apply, project, and reduce precision to prevent rational blowup
        let conjugated = op.apply(&current).ok()?;
        current = crate::engine::pi_g_project(&conjugated);
        reduce_delta_precision(&mut current, 10000); // max denominator 10000

        // Compose
        composed_mat = matrix::mul(&op.matrix, &composed_mat);
        composed_inv = matrix::mul(&composed_inv, &op.matrix_inv);

        // Check convergence
        let d = operator_distance(
            &Operator { id: 0, matrix: composed_mat.clone(), matrix_inv: composed_inv.clone(), det_sign_positive: true },
            source, target,
        );
        if d < Q::new(BigInt::from(1), BigInt::from(1000)) { break; }
    }

    let det_val = matrix::det(&composed_mat);
    if det_val <= Q::zero() { return None; }

    let final_dist = operator_distance(
        &Operator { id: 0, matrix: composed_mat.clone(), matrix_inv: composed_inv.clone(), det_sign_positive: true },
        source, target,
    );

    Some((
        Operator { id: 0, matrix: composed_mat, matrix_inv: composed_inv, det_sign_positive: true },
        dist_initial,
        final_dist,
    ))
}

/// Discrete operator search: try operator families at multiple scales.
/// For each candidate operator, measure distance to target.
/// Return the operator with smallest distance.
///
/// This handles FINITE transformations (permutations, rotations, reflections)
/// that the perturbation-based search misses because they're not reachable
/// by small epsilon perturbations from identity.
pub fn search_operator_discrete(
    source: &Delta,
    target: &Delta,
) -> Option<(Operator, Q, Q)> {
    let n = source.dim;
    let dirs = matrix::independent_dims(n);
    let dist_initial = operator_distance(
        &Operator { id: 0, matrix: matrix::identity(n), matrix_inv: matrix::identity(n), det_sign_positive: true },
        source, target,
    );

    if dist_initial.is_zero() { return None; } // already equal

    let mut best_op: Option<Operator> = None;
    let mut best_dist = dist_initial.clone();

    // Try shear operators at multiple scales
    let scales = [
        Q::new(BigInt::from(1), BigInt::from(20)),
        Q::new(BigInt::from(1), BigInt::from(5)),
        Q::new(BigInt::from(1), BigInt::from(2)),
        Q::new(BigInt::from(1), BigInt::from(1)),
        Q::new(BigInt::from(2), BigInt::from(1)),
        Q::new(BigInt::from(-1), BigInt::from(1)),
        Q::new(BigInt::from(-1), BigInt::from(2)),
    ];

    for &(r, s) in &dirs {
        for scale in &scales {
            let mut eps = vec![Q::zero(); dirs.len()];
            for (idx, &(dr, ds)) in dirs.iter().enumerate() {
                if dr == r && ds == s { eps[idx] = scale.clone(); }
            }
            if let Some(op) = matrix::operator_from_epsilons(&eps, &dirs, n, 0) {
                let d = operator_distance(&op, source, target);
                if d < best_dist {
                    best_dist = d;
                    best_op = Some(op);
                }
            }
            // Also try negative
            let mut eps_neg = vec![Q::zero(); dirs.len()];
            for (idx, &(dr, ds)) in dirs.iter().enumerate() {
                if dr == r && ds == s { eps_neg[idx] = -scale.clone(); }
            }
            if let Some(op) = matrix::operator_from_epsilons(&eps_neg, &dirs, n, 0) {
                let d = operator_distance(&op, source, target);
                if d < best_dist {
                    best_dist = d;
                    best_op = Some(op);
                }
            }
        }
    }

    // Also try the perturbation-based search as a candidate
    if let Some((pert_op, _, d_pert)) = search_operator(source, target) {
        if d_pert < best_dist {
            best_dist = d_pert;
            best_op = Some(pert_op);
        }
    }

    best_op.map(|op| (op, dist_initial, best_dist))
}


// ═══════════════════════════════════════════════════════════════════════
// UNDERSTAND — Transformation Encoding (UNDERSTAND.1-9)
//
// The encoding that produces UNDERSTANDING, not just measurement.
// Delta dimensions = CONFIGURATIONS (training examples).
// Delta entries = TRANSFORMATIONS between configurations.
// Cocycle condition = RULE CONSISTENCY.
// C(Δ) = 0 means the system UNDERSTANDS the pattern.
// ═══════════════════════════════════════════════════════════════════════

/// UNDERSTAND.1 — Encode training examples as a configuration-space Delta.
///
/// Given n training pairs (input_k, output_k), configurations are the
/// TRANSFORMATIONS themselves. Δ_ij encodes how transformation i differs
/// from transformation j.
///
/// For each pair k, compute the per-cell change: change_k[cell] = output_k[cell] - input_k[cell].
/// Δ_ij = change_j - change_i (as a vector over cells).
/// This IS antisymmetric: change_j - change_i = -(change_i - change_j).
///
/// The cocycle condition checks: is the pattern of changes across examples
/// transitively consistent? C(Δ) = 0 means ALL examples show the SAME
/// transformation structure.
pub fn encode_transformations(pairs: &[(Vec<i64>, Vec<i64>)]) -> Option<Delta> {
    if pairs.is_empty() { return None; }
    let cells = pairs[0].0.len();
    if pairs.iter().any(|(i, o)| i.len() != cells || o.len() != cells) { return None; }

    let n = pairs.len(); // number of configurations = number of training examples
    let m = cells;       // coordinate dimension = number of cells

    // Compute per-example change vectors
    let changes: Vec<Vec<Q>> = pairs.iter().map(|(inp, out)| {
        (0..cells).map(|c| Q::new(BigInt::from(out[c] - inp[c]), BigInt::from(1))).collect()
    }).collect();

    // Build Delta: Δ_ij,l = change_j[l] - change_i[l]
    let mut delta = Delta::zero(n, m);
    for i in 0..n {
        for j in (i + 1)..n {
            let mut coords = Vec::with_capacity(m);
            let mut neg_coords = Vec::with_capacity(m);
            for l in 0..m {
                let diff = &changes[j][l] - &changes[i][l];
                neg_coords.push(-diff.clone());
                coords.push(diff);
            }
            delta.entries[i][j] = coords;
            delta.entries[j][i] = neg_coords;
        }
    }

    Some(delta)
}

/// UNDERSTAND.2 — Measure understanding: do all examples show the same rule?
///
/// Uses VARIANCE of per-cell changes across examples, not the cocycle condition.
/// (H¹=0 theorem: cocycle on configuration differences is always zero.)
///
/// Returns (variance, understanding_level):
///   variance = 0: all examples show the same per-cell change → understood
///   variance > 0: examples differ → variance measures inconsistency
///   understanding_level = 1 / (1 + variance) → 1 = perfect, → 0 = no understanding
pub fn measure_understanding(pairs: &[(Vec<i64>, Vec<i64>)]) -> (Q, Q) {
    if pairs.is_empty() { return (Q::zero(), Q::zero()); }
    let cells = pairs[0].0.len();
    if pairs.iter().any(|(i, o)| i.len() != cells || o.len() != cells) {
        return (Q::new(BigInt::from(-1), BigInt::from(1)), Q::zero());
    }

    let n = pairs.len();
    if n < 2 {
        // Single example — trivially "understood" (no contradiction possible)
        return (Q::zero(), Q::one());
    }

    // Compute per-cell changes for each example
    let changes: Vec<Vec<i64>> = pairs.iter()
        .map(|(inp, out)| (0..cells).map(|c| out[c] - inp[c]).collect())
        .collect();

    // Compute variance: Σ_examples Σ_cells (change - mean_change)²
    let _n_q = Q::new(BigInt::from(n as i64), BigInt::from(1));
    let mut variance = Q::zero();

    for c in 0..cells {
        // Mean change at cell c
        let sum: i64 = changes.iter().map(|ch| ch[c]).sum();
        let mean = Q::new(BigInt::from(sum), BigInt::from(n as i64));

        // Variance at cell c
        for ch in &changes {
            let diff = Q::new(BigInt::from(ch[c]), BigInt::from(1)) - &mean;
            variance = &variance + &(&diff * &diff);
        }
    }

    let understanding = Q::one() / &(Q::one() + &variance);

    (variance, understanding)
}

/// UNDERSTAND.3 — Extract the common transformation rule from understood examples.
///
/// When C(Δ) = 0, all examples show the same per-cell change pattern.
/// The common rule is the MEAN change vector across examples.
/// Returns the per-cell change as Vec<Q> (exact rational).
pub fn extract_rule(pairs: &[(Vec<i64>, Vec<i64>)]) -> Option<Vec<Q>> {
    if pairs.is_empty() { return None; }
    let cells = pairs[0].0.len();
    let n = pairs.len();

    let mut mean_change = vec![Q::zero(); cells];
    for (inp, out) in pairs {
        if inp.len() != cells || out.len() != cells { return None; }
        for c in 0..cells {
            mean_change[c] = &mean_change[c] + &Q::new(BigInt::from(out[c] - inp[c]), BigInt::from(1));
        }
    }
    let n_q = Q::new(BigInt::from(n as i64), BigInt::from(1));
    for c in 0..cells {
        mean_change[c] = &mean_change[c] / &n_q;
    }

    Some(mean_change)
}

/// UNDERSTAND.3 — Apply a discovered rule to a test input.
///
/// The rule is a per-cell change vector. Apply it to produce the output.
/// Rounds rational changes to nearest integer for grid values.
pub fn apply_rule(test_input: &[i64], rule: &[Q]) -> Vec<i64> {
    test_input.iter().zip(rule.iter()).map(|(&val, change)| {
        let result = &Q::new(BigInt::from(val), BigInt::from(1)) + change;
        // Round to nearest integer
        let numer: i64 = result.numer().try_into().unwrap_or(0);
        let denom: i64 = result.denom().try_into().unwrap_or(1);
        if denom == 0 { 0 } else { (numer + denom / 2) / denom }
    }).collect()
}

/// UNDERSTAND.4 — Transformation signature: hash the STRUCTURE of the rule.
///
/// Two puzzles with the same rule type get the same signature.
/// Encodes: which cells change, by how much (relative), in which pattern.
pub fn transformation_signature(pairs: &[(Vec<i64>, Vec<i64>)]) -> [u8; 4] {
    use tiny_keccak::{Hasher, Keccak};

    let mut hasher = Keccak::v256();
    hasher.update(b"SAIOS-TRANSFORM-SIG-v1");

    if let Some(rule) = extract_rule(pairs) {
        // Hash: which cells change (bitmap)
        let mut changes_bitmap: u64 = 0;
        for (i, r) in rule.iter().enumerate() {
            if !r.is_zero() {
                changes_bitmap |= 1 << (i % 64);
            }
        }
        hasher.update(&changes_bitmap.to_be_bytes());

        // Hash: are changes uniform?
        let first_nonzero = rule.iter().find(|r| !r.is_zero());
        if let Some(first) = first_nonzero {
            let uniform = rule.iter().all(|r| r.is_zero() || r == first);
            hasher.update(if uniform { b"uniform" } else { b"varied" });
        }

        // Hash: number of changing cells
        let change_count = rule.iter().filter(|r| !r.is_zero()).count() as u32;
        hasher.update(&change_count.to_be_bytes());
    }

    let mut hash = [0u8; 32];
    hasher.finalize(&mut hash);
    let mut sig = [0u8; 4];
    sig.copy_from_slice(&hash[..4]);
    sig
}

/// UNDERSTAND.7 — Complete understanding pipeline for ARC puzzles.
///
/// Given training pairs and test input:
/// 1. Encode transformations (UNDERSTAND.1)
/// 2. Measure understanding (UNDERSTAND.2)
/// 3. If understood (C=0 or close): extract rule, apply to test
/// 4. If not understood: use residuals to identify inconsistencies
///
/// Returns (prediction, coherence, understanding_level)
pub fn understand_and_solve(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: &[i64],
) -> Option<(Vec<i64>, Q, Q)> {
    if train_pairs.is_empty() { return None; }
    let cells = train_pairs[0].0.len();
    if test_input.len() != cells { return None; }

    // Measure understanding
    let (coherence, understanding) = measure_understanding(train_pairs);

    // Extract the common rule
    let rule = extract_rule(train_pairs)?;

    // Apply rule to test input
    let prediction = apply_rule(test_input, &rule);

    Some((prediction, coherence, understanding))
}

