    fn test_transformation_signature_different() {
        let pairs1 = vec![(vec![0, 1, 2], vec![2, 3, 4])]; // +2 uniform
        let pairs2 = vec![(vec![0, 1, 2], vec![0, 2, 4])]; // ×2 (non-uniform additive)
        let sig1 = transformation_signature(&pairs1);
        let sig2 = transformation_signature(&pairs2);
        assert_ne!(sig1, sig2, "Different rule types must have different signatures");
    }

    #[test]
    fn test_understand_real_arc_color_shift() {
        // Real ARC puzzle: each cell shifts by +1
        // Input: [[3,1,2],[3,1,2],[3,1,2]] → Output: [[4,5,6],[4,5,6],[4,5,6]]
        // Wait — that's +1,+4,+4, not uniform. Let me check:
        // 3→4 (+1), 1→5 (+4), 2→6 (+4). Not uniform!
        // But it IS consistent across rows (every row has the same change).
        let train = vec![
            (vec![3,1,2, 3,1,2, 3,1,2], vec![4,5,6, 4,5,6, 4,5,6]),
        ];
        let test = vec![3,1,2, 3,1,2, 3,1,2]; // same input
        let result = understand_and_solve(&train, &test);
        assert!(result.is_some());
        let (derived, _, _) = result.unwrap();
        assert_eq!(derived, vec![4,5,6, 4,5,6, 4,5,6],
            "Must reproduce the transformation exactly from single example");
    }

    // ─── PERC.0 — Domain-neutral encoding tests ────────────────────

    #[test]
    fn test_encode_relational_produces_valid_delta() {
        let entities = vec![
            vec![qr(1,1), qr(2,1)],
            vec![qr(3,1), qr(5,1)],
            vec![qr(7,1), qr(11,1)],
        ];
        let delta = encode_relational(&entities);
        assert_eq!(delta.dim, 3);
        assert_eq!(delta.m, 2);

        // Δ_{01} = entity_1 - entity_0 = (2, 3)
        assert_eq!(delta.entries[0][1][0], qr(2, 1));
        assert_eq!(delta.entries[0][1][1], qr(3, 1));

        // Antisymmetry: Δ_{10} = -Δ_{01}
        assert_eq!(delta.entries[1][0][0], qr(-2, 1));
        assert_eq!(delta.entries[1][0][1], qr(-3, 1));

        // Zero diagonal
        assert!(delta.entries[0][0][0].is_zero());
        assert!(delta.entries[1][1][0].is_zero());
    }

    #[test]
    fn test_encode_relational_i64_single_dim() {
        let delta = encode_relational_i64(&[10, 20, 30]);
        assert_eq!(delta.dim, 3);
        assert_eq!(delta.m, 1);
        assert_eq!(delta.entries[0][1][0], qr(10, 1));
        assert_eq!(delta.entries[0][2][0], qr(20, 1));
        assert_eq!(delta.entries[1][2][0], qr(10, 1));
    }

