    #[test]
    fn test_knowledge_record_stores_comprehension() {
        // Verify KnowledgeBase stores and recalls ComprehensionRecord
        use crate::thinking::{KnowledgeBase, Thought, ComprehensionRecord};
        let mut kb = KnowledgeBase::new();
        let comp = ComprehensionRecord {
            sparse: true, object_count: 3,
            refraction_transparent: false,
            semantic_intent: "relate",
            cognitive_path: "evolved",
            transmutation_signal: true,
            partial_operator: None,
        };
        kb.remember([0xAA, 0xBB, 0xCC, 0xDD], Thought::Identity, 3, 3, comp);

        let (thought, recalled_comp) = kb.recognize(&[0xAA, 0xBB, 0xCC, 0xDD]).unwrap();
        assert!(matches!(thought, Thought::Identity));
        assert_eq!(recalled_comp.object_count, 3);
        assert_eq!(recalled_comp.semantic_intent, "relate");
        assert!(recalled_comp.transmutation_signal);
        assert!(!recalled_comp.refraction_transparent);
    }

    // ── Residual Topology tests ──

    #[test]
    fn test_residual_topology_zero_deviation() {
        // Perfect match → no topology
        let derived = vec![1, 2, 3, 4];
        let expected = vec![1, 2, 3, 4];
        let topo = ResidualTopology::measure(&derived, &expected, 2, 2);
        assert_eq!(topo.magnitude, 0);
        assert_eq!(topo.deviating_cells, 0);
        assert_eq!(topo.correct_cells, 4);
        assert!(topo.silhouette_clusters.is_empty());
    }

    #[test]
    fn test_residual_topology_uniform_deviation() {
        // Every cell off by +1 → uniform deviation
        let derived  = vec![2, 3, 4, 5];
        let expected = vec![1, 2, 3, 4];
        let topo = ResidualTopology::measure(&derived, &expected, 2, 2);
        assert_eq!(topo.magnitude, 4);
        assert_eq!(topo.deviating_cells, 4);
        assert!(topo.uniformity > Q::new(BigInt::from(3), BigInt::from(4)), "all cells deviate by the same amount → uniform");
    }

    #[test]
    fn test_residual_topology_structured_cluster() {
        // 3x3 grid, deviation forms a connected cluster in the bottom-right 2x2
        let derived  = vec![0, 0, 0,
                            0, 5, 5,
                            0, 5, 5];
        let expected = vec![0, 0, 0,
                            0, 0, 0,
                            0, 0, 0];
        let topo = ResidualTopology::measure(&derived, &expected, 3, 3);
        assert_eq!(topo.magnitude, 20);
        assert_eq!(topo.deviating_cells, 4);
        assert_eq!(topo.correct_cells, 5);
        // The 4 deviating cells form a connected cluster → structured
        assert!(!topo.silhouette_clusters.is_empty(),
            "deviating cells should form silhouette clusters");
        assert!(topo.uniformity > Q::new(BigInt::from(3), BigInt::from(4)), "all deviating cells have the same value (5)");
    }

    #[test]
    fn test_residual_topology_isolated_noise() {
        // 3x3 grid, deviation at scattered non-adjacent cells
        let derived  = vec![1, 0, 0,
                            0, 0, 0,
                            0, 0, 2];
        let expected = vec![0, 0, 0,
                            0, 0, 0,
                            0, 0, 0];
        let topo = ResidualTopology::measure(&derived, &expected, 3, 3);
        assert_eq!(topo.magnitude, 3);
        assert_eq!(topo.deviating_cells, 2);
        // Scattered non-adjacent → each cell is its own cluster → low cohesion
        assert!(topo.uniformity <= Q::new(BigInt::from(3), BigInt::from(4)), "different deviation values (1 and 2)");
    }

    #[test]
    fn test_residual_topology_on_cognition() {
        // When cognize produces a non-zero residual, residual_topology should be present
        // Use a puzzle that won't perfectly resolve
        let pairs = vec![(
            vec![1, 2, 3, 4, 5, 6, 7, 8, 9],
            vec![9, 8, 7, 6, 5, 4, 3, 2, 1],
        )];
        let cog = cognize(&pairs, &[1, 2, 3, 4, 5, 6, 7, 8, 9], None);
        // Whether residual is 0 or not depends on the rule — but the field exists
        if cog.perception.coherence < num_rational::Ratio::one() {
            assert!(cog.residual_topology.is_some(),
                "non-full coherence should produce residual_topology");
            let topo = cog.residual_topology.unwrap();
            assert!(topo.deviating_cells > 0);
        } else {
            assert!(cog.residual_topology.is_none(),
                "full coherence should have no topology");
        }
    }

    #[test]
    fn test_residual_topology_sparsity() {
        // 4x4 grid, 2 deviating cells out of 16 → sparsity = 2/16 = 1/8
        let mut derived = vec![0i64; 16];
        let expected = vec![0i64; 16];
        derived[5] = 3;
        derived[10] = 7;
        let topo = ResidualTopology::measure(&derived, &expected, 4, 4);
        assert_eq!(topo.deviating_cells, 2);
        assert_eq!(topo.sparsity, qr(2, 16));
    }

    #[test]
    fn test_residual_topology_aggregate() {
        // Two pairs with similar deviation patterns
        let d1 = vec![0, 0, 5, 5];
        let e1 = vec![0, 0, 0, 0];
        let d2 = vec![0, 0, 3, 3];
        let e2 = vec![0, 0, 0, 0];
        let topo = ResidualTopology::measure_aggregate(
            &[d1, d2], &[e1, e2], 2, 2,
        );
        // Aggregate deviation: [0, 0, 5+3, 5+3] = [0, 0, 8, 8]
        assert_eq!(topo.deviating_cells, 2);
        assert!(topo.magnitude > 0);
        // Same positions deviate in both pairs → systematic gap
    }

    // ── RefractiveLens tests ──

    #[test]
    fn test_prime_factors() {
        assert_eq!(prime_factors(1), Vec::<u32>::new());
        assert_eq!(prime_factors(2), vec![2]);
        assert_eq!(prime_factors(12), vec![2, 3]);
        assert_eq!(prime_factors(500), vec![2, 5]);
        assert_eq!(prime_factors(521), vec![521]); // prime
        assert_eq!(prime_factors(1001), vec![7, 11, 13]);
    }

    #[test]
    fn test_build_refractive_lens_from_delta() {
        // Node 42: Δ[0][1] = 1042/1000 = 521/500
        let mut delta = crate::engine::Delta::zero(3, 1);
        delta.set_antisym(0, 1, vec![qr(521, 500)]);
        delta.set_antisym(1, 2, vec![qr(271, 500)]);
        delta.set_antisym(0, 2, vec![qr(792, 500)]);

        let lens = build_refractive_lens(&delta);

        // Should have torsion orders from prime factors of 521, 271, 792, 500
        // 500 = 2² × 5³ → {2, 5}
        // 521 is prime → {521}
        // 271 is prime → {271}
        // 792 = 2³ × 3² × 11 → {2, 3, 11}
        // Combined: {2, 3, 5, 11, 271, 521}
        assert!(lens.torsion_orders.contains(&2));
        assert!(lens.torsion_orders.contains(&3));
        assert!(lens.torsion_orders.contains(&5));
        assert!(lens.torsion_orders.contains(&11));
        assert_eq!(lens.relational_weights.len(), 3);
    }

    #[test]
    fn test_different_deltas_produce_different_spectra() {
        // Node 1: entries based on nid=1
        let mut d1 = crate::engine::Delta::zero(3, 1);
        d1.set_antisym(0, 1, vec![qr(1001, 1000)]); // 1001 = 7 × 11 × 13
        d1.set_antisym(1, 2, vec![qr(501, 1000)]);   // 501 = 3 × 167
        d1.set_antisym(0, 2, vec![qr(1502, 1000)]);

        // Node 7: entries based on nid=7
        let mut d7 = crate::engine::Delta::zero(3, 1);
        d7.set_antisym(0, 1, vec![qr(1007, 1000)]); // 1007 = 19 × 53
        d7.set_antisym(1, 2, vec![qr(507, 1000)]);   // 507 = 3 × 169 = 3 × 13²
        d7.set_antisym(0, 2, vec![qr(1514, 1000)]);

        let lens1 = build_refractive_lens(&d1);
        let lens7 = build_refractive_lens(&d7);

        // Both share common primes from denom 1000 (2, 5), but differ in numer primes
        // Node 1 has {7, 11, 13, 167}. Node 7 has {19, 53, 13}.
        assert_ne!(lens1.torsion_orders, lens7.torsion_orders,
            "different Δ_k must produce different torsion spectra");
    }

    #[test]
    fn test_raw_resonance_varies_by_position() {
        let mut delta = crate::engine::Delta::zero(3, 1);
        delta.set_antisym(0, 1, vec![qr(3, 1)]); // torsion order 3
        delta.set_antisym(1, 2, vec![qr(1, 2)]); // torsion order 2
        delta.set_antisym(0, 2, vec![qr(7, 2)]); // torsion orders 7, 2

        let lens = build_refractive_lens(&delta);

        // Raw resonance at (0,0) should differ from (1,1)
        let b00 = lens.raw_resonance(0, 0);
        let b11 = lens.raw_resonance(1, 1);
        let b03 = lens.raw_resonance(0, 3);

        assert_ne!(b00, b11, "resonance and anti-resonance must produce different values");
        assert_ne!(b00, b03, "different resonance patterns at different positions");
    }

    #[test]
    fn test_different_lenses_produce_different_grid_biases() {
        let mut d1 = crate::engine::Delta::zero(3, 1);
        d1.set_antisym(0, 1, vec![qr(7, 1)]);
        d1.set_antisym(1, 2, vec![qr(1, 1)]);
        d1.set_antisym(0, 2, vec![qr(8, 1)]);

        let mut d2 = crate::engine::Delta::zero(3, 1);
        d2.set_antisym(0, 1, vec![qr(11, 1)]);
        d2.set_antisym(1, 2, vec![qr(1, 1)]);
        d2.set_antisym(0, 2, vec![qr(12, 1)]);

        let lens1 = build_refractive_lens(&d1);
        let lens2 = build_refractive_lens(&d2);

        // Grid-normalized biases across a 7x7 grid
        let biases1 = lens1.grid_biases(7, 7);
        let biases2 = lens2.grid_biases(7, 7);

        assert_ne!(biases1, biases2,
            "different torsion spectra must produce different spatial bias patterns");
    }

    #[test]
    fn test_refractive_index_measures_spatial_differentiation() {
        let mut delta = crate::engine::Delta::zero(3, 1);
        delta.set_antisym(0, 1, vec![qr(3, 1)]);
        delta.set_antisym(1, 2, vec![qr(5, 1)]);
        delta.set_antisym(0, 2, vec![qr(8, 1)]);

        let lens = build_refractive_lens(&delta);
        let ri = lens.refractive_index(7, 7);

        // Refractive index should be positive (non-zero spatial variation)
        assert!(ri > Q::zero(), "lens with non-trivial torsion orders should refract");
    }

    #[test]
    fn test_lens_refracts_training_pairs_differently() {
        // Two different lenses refract the same training pair differently
        // Lens 1: primes from 3/1=3, 4/1=2² → torsion orders {2, 3}
        let mut d1 = crate::engine::Delta::zero(3, 1);
        d1.set_antisym(0, 1, vec![qr(3, 1)]);
        d1.set_antisym(1, 2, vec![qr(1, 1)]);
        d1.set_antisym(0, 2, vec![qr(4, 1)]);

        // Lens 2: primes from 7/1=7, 8/1=2³ → torsion orders {2, 7}
        let mut d2 = crate::engine::Delta::zero(3, 1);
        d2.set_antisym(0, 1, vec![qr(7, 1)]);
        d2.set_antisym(1, 2, vec![qr(1, 1)]);
        d2.set_antisym(0, 2, vec![qr(8, 1)]);

        let lens1 = build_refractive_lens(&d1);
        let lens2 = build_refractive_lens(&d2);

        // 3x3 grid — use grid_biases for centered+normalized biases
        let biases1 = lens1.grid_biases(3, 3);
        let biases2 = lens2.grid_biases(3, 3);

        let input: Vec<i64> = vec![0, 1, 2, 3, 4, 5, 6, 7, 8];

        let refracted1: Vec<i64> = input.iter().enumerate()
            .map(|(idx, &v)| v.wrapping_add(biases1[idx]))
            .collect();
        let refracted2: Vec<i64> = input.iter().enumerate()
            .map(|(idx, &v)| v.wrapping_add(biases2[idx]))
            .collect();

        assert_ne!(refracted1, refracted2,
            "different lenses must produce different refracted observations");
    }

    #[test]
    fn test_lens_works_at_any_observation_size() {
        // A 3x3 Δ_k refracts a 21x21 observation (441 cells) — the critical case
        let mut delta = crate::engine::Delta::zero(3, 1);
        delta.set_antisym(0, 1, vec![qr(521, 500)]);
        delta.set_antisym(1, 2, vec![qr(271, 500)]);
        delta.set_antisym(0, 2, vec![qr(792, 500)]);

        let lens = build_refractive_lens(&delta);

        // Grid-normalized biases for 21x21
        let biases = lens.grid_biases(21, 21);
        let input: Vec<i64> = (0..441).map(|i| i % 10).collect();

        let refracted: Vec<i64> = input.iter().enumerate()
            .map(|(idx, &v)| v.wrapping_add(biases[idx]))
            .collect();

        // Must differ from original (lens has non-trivial torsion orders)
        assert_ne!(refracted, input,
            "3x3 lens must refract 441-cell observation through torsion resonance");

        // Count how many cells are modified
        let modified = input.iter().zip(&refracted)
            .filter(|(&a, &b)| a != b)
            .count();

        // Should modify substantially more than the old 3-cell overlap
        assert!(modified > 20,
            "torsion resonance should modulate many cells, not just 3 overlap; got {}/441", modified);

        // All biases should be bounded to [-2, +2]
        assert!(biases.iter().all(|&b| b >= -2 && b <= 2),
            "grid_biases must be bounded to [-2, +2]");
    }

    #[test]
    fn test_zero_delta_produces_neutral_lens() {
        let delta = crate::engine::Delta::zero(3, 1);
        let lens = build_refractive_lens(&delta);

        // Zero entries → torsion_orders = [1] (fallback)
        assert_eq!(lens.torsion_orders, vec![1]);
        // torsion order 1 is skipped in raw_resonance (t <= 1)
        assert_eq!(lens.raw_resonance(5, 5), 0, "zero Delta should produce zero resonance");
        // Grid biases should all be zero
        let biases = lens.grid_biases(5, 5);
        assert!(biases.iter().all(|&b| b == 0), "zero Delta should produce zero biases");
    }
